  ('839', '청국장 시래기전', '반찬', '대두 10g, 시레기 60g, 청고추 2g, 홍고추 2g, 새우살 13g, 밀가루 6g, 도토리가루 2g, 달걀 6.5g, 식용유 1g', '["대두","시레기","청고추","홍고추","새우살","밀가루","도토리가루","달걀","식용유"]'::jsonb, ARRAY['30b5d53c-d247-4f04-9b50-c0f728e65cf9','6f10b4ad-53a2-4a07-ba89-19a6b074373d','aab3b0b9-d346-4697-a1c8-1b1530153788','c7d438a6-34d6-423f-905d-446b839e2f39','a7a59e81-de3d-4893-b56a-b2218732a25b']::uuid[], '[{"step":1,"text":"시레기는 1cm 길이로 자른다.","imageUrl":null},{"step":2,"text":"저나트륨 청국장은 굵게 다진다.","imageUrl":null},{"step":3,"text":"청, 홍고추와 새우 살도 굵게 다진다.","imageUrl":null},{"step":4,"text":"불에 준비된 청국장, 시래기, 청, 홍고추를 도토리가루와 밀가루, 물, 달걀을 넣어 되직하게 반죽한다.","imageUrl":null},{"step":5,"text":"팬에 식용유를 두르고 반죽을 부친다.","imageUrl":null},{"step":6,"text":"반죽 위에 새우 살을 얹어 전을 부친다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053439_1416213279588.jpg', 118.4, 14.7, 7, 4, 49),
  ('840', '카레소스를 얹은 두부 스테이크', '반찬', '두부 67g, 애호박 17g, 양송이 33g, 가지 17g, 파프리카 17g, 사과 50g, 감자 33g, 카레가루 10g, 식용유 2g, 녹말가루 5g, 물 5g', '["두부","애호박","양송이","가지","파프리카","사과","감자","카레가루","식용유","녹말가루","물"]'::jsonb, ARRAY['4566cac5-9166-4c0d-906a-bfc7360f8f5b','88c94a13-dc8a-4e66-ab19-08fc2ea82c77','48a4fd5a-e4f6-467b-9e3f-445334e0ee04','3e12cf79-2cde-4309-9f7c-4eccce3fde28','5e79d288-1400-4817-bd20-e5e6041821b1','c85a52b9-c3b4-4a76-951c-bb40edeb3adb','20894da1-739d-4d52-b5fe-4943bd3492d5','495b9f1e-aa3b-4506-9bb8-feb0a493901e','a7a59e81-de3d-4893-b56a-b2218732a25b','6613d1d9-80a2-4ce4-9d3d-647203197e53','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"두부를 두께 2cm로 썰어 원형틀로 찍어 준비한다.","imageUrl":null},{"step":2,"text":"준비한 채소는 작은 정육면체로 썰어 팬에 살짝 볶는다.","imageUrl":null},{"step":3,"text":"물과 카레가루를 섞어 끓이다가 감자를 넣어 끓이고 감자가 거의 익을 때쯤에 나머지 채소를 넣어 끓인다.","imageUrl":null},{"step":4,"text":"물과 녹말가루를 섞어 3의 카레소스의 농도를 맞춘다.","imageUrl":null},{"step":5,"text":"가열된 팬에 두부를 노릇노릇하게 지진다.","imageUrl":null},{"step":6,"text":"준비한 소스를 두부 스테이크에 뿌려낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053440_1416213280344.jpg', 199.4, 27.8, 10.1, 7.5, 481),
  ('843', '녹차 파나코타', '후식', '녹차가루 6g, 판젤라틴 5.3g, 설탕 32g, 물 15g, 생크림 30g, 우유 55.7g, 바닐라에센스 0.1g, 통조림단팥장식용,민트장식용', '["녹차가루","판젤라틴","설탕","물","생크림","우유","바닐라에센스","통조림단팥장식용","민트장식용"]'::jsonb, ARRAY['e1ee1919-9a32-462f-ae14-55c7a47ce0a0','06e6f3e7-0293-469d-a338-11a610f3e71b','94786475-832c-4f97-aab7-bf6fbbe2236b','af187077-b7f6-4b0e-9e99-f844f6359ac2','e937397f-54e2-49df-997a-f393c58360be']::uuid[], '[{"step":1,"text":"볼에 물을 담고 판 젤라틴을 넣어 3분 가량 불린 뒤 건진다.","imageUrl":null},{"step":2,"text":"냄비에 녹차가루와 소량의 물을 넣고 진하게 섞는다.","imageUrl":null},{"step":3,"text":"2에 우유와 크림, 설탕, 바닐라 에센스를 넣고 약한 불에서 설탕이 녹을 정도로 끓인다.","imageUrl":null},{"step":4,"text":"3에 불린 젤라틴을 넣고 젤라틴이 녹을 때까지 가열한다.","imageUrl":null},{"step":5,"text":"용기에 녹차 파나코타를 부은 후 실온에서 식힌다.","imageUrl":null},{"step":6,"text":"냉장고에서 한번 더 식혀 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053442_1416213282795.jpg', 310.3, 43.7, 4.9, 13.9, 62),
  ('1121', '자색고구마찹쌀푸딩', '후식', '자색고구마(40g), 우유(120g),
찹쌀가루(4g), 소금(0.1g)', '["자색고구마","우유","찹쌀가루","소금"]'::jsonb, ARRAY['4b4f0113-01cf-4dc6-ae1f-30f09e99746b','e937397f-54e2-49df-997a-f393c58360be','4cb11562-015f-4ab5-969f-0ea8483a0b42','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"자색고구마는 솔로 문질러 깨끗하게 씻는다.","imageUrl":null},{"step":2,"text":"껍질을 벗기고 찐다.","imageUrl":null},{"step":3,"text":"찐 자색고구마와 우유, 소금을 믹서에 곱게 간다.","imageUrl":null},{"step":4,"text":"3번을 고운 체에 걸러 덩어리를 없앤다.","imageUrl":null},{"step":5,"text":"볼에 4번을 넣고 찹쌀가루를 넣어 잘 풀리도록 젓는다.","imageUrl":null},{"step":6,"text":"5번을 끓이다가 엉기기 시작하면 그릇에 담아 차게 식힌다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01121_2.png', 165.2, 29.2, 4.1, 3.6, 13.1),
  ('1122', '꽃설기', '후식', '멥쌀가루(112g), 대추(5알),
