  ('1128', '자두 라떼', '후식', '자두(200g), 우유(250g), 꿀(10g), 물(15g)', '["자두","우유","꿀","물"]'::jsonb, ARRAY['e937397f-54e2-49df-997a-f393c58360be','286d1783-cd34-4aae-ac8b-006529ec8bc5','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"자두를 깨끗이 씻어 얼린다.","imageUrl":null},{"step":2,"text":"얼린 자두와 꿀, 물을 믹서에 넣고 간다.","imageUrl":null},{"step":3,"text":"믹서에 간 자두의 일부를 얼음틀에 넣고 얼린다.","imageUrl":null},{"step":4,"text":"믹서에 간 자두를 컵에 담는다.","imageUrl":null},{"step":5,"text":"3번을 컵에 담는다.","imageUrl":null},{"step":6,"text":"우유를 붓는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01128_2.png', 210, 30.3, 6.2, 7.1, 18.5),
  ('1129', '와인배숙', '후식', '배(1/2개), 사과(1/2개), 레드와인(200g),
계피(5g), 통후추(6알)', '["배","사과","레드와인","계피","통후추"]'::jsonb, ARRAY['eccf67f1-41f0-4a25-b238-6b9e7332c9e1','c85a52b9-c3b4-4a76-951c-bb40edeb3adb','e16eaf50-ebd3-4933-a774-3ce6fc92593f','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"배와 사과는 스쿠퍼로 동그랗게 모양을 만든다.","imageUrl":null},{"step":2,"text":"냄비에 와인을 넣고 계피, 통후추와 함께 약불에서 끓인다.","imageUrl":null},{"step":3,"text":"와인이 끓기 시작하면 배와 사과를 넣고 양이 반이 될 때까지 졸인다.","imageUrl":null},{"step":4,"text":"차갑게 식힌다.","imageUrl":null},{"step":5,"text":"4번을 용기에 담는다.","imageUrl":null},{"step":6,"text":"졸여진 배와 사과를 과일꼬지에 꽂아 곁들인다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01129_2.png', 107.5, 25.4, 0.9, 0.3, 16.4),
  ('1130', '유자애(愛) 빠지다', '후식', '유자(200g), 밤(25g), 대추(15g), 배(50g),
석류(20g), 꿀(10g), 소금(0.5g), 물(300g)', '["유자","밤","대추","배","석류","꿀","소금","물"]'::jsonb, ARRAY['5e4a7ae8-e12e-48b6-88d5-fc3521d3dce8','b371c5d2-f12b-47ee-9a87-26efd09db09d','eccf67f1-41f0-4a25-b238-6b9e7332c9e1','286d1783-cd34-4aae-ac8b-006529ec8bc5','2cf0c12b-f248-4012-8f53-303c730a7b3d','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"유자는 십자로 갈집을 낸 뒤 끓는 소금물에 데쳐 껍질을 깨끗이 한다.","imageUrl":null},{"step":2,"text":"유자는 속을 꺼내 씨를 제거하고 유자속과 속껍질을 얇게 채 썬다.","imageUrl":null},{"step":3,"text":"밤, 대추, 배는 채 썰고 2번과 섞어 소를 만든다.","imageUrl":null},{"step":4,"text":"속을 빼낸 유자에 소를 2/3쯤 채워 입구를 실로 묶는다.","imageUrl":null},{"step":5,"text":"유자묶음을 용기에 채워 넣은 후 꿀물을 붓고 잘 밀봉하여 냉장고에 보관한다.","imageUrl":null},{"step":6,"text":"3~4주 정도 숙성한 뒤 석류를 곁들여 먹는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01130_2.png', 153.2, 34.2, 3.4, 0.3, 15.2),
  ('1131', '쌀콩죽 요거트', '후식', '우유(65g), 배(60g), 고구마(35g),
요거트(3g), 쌀가루(5g), 메주콩(5g)', '["우유","배","고구마","요거트","쌀가루","메주콩"]'::jsonb, ARRAY['e937397f-54e2-49df-997a-f393c58360be','eccf67f1-41f0-4a25-b238-6b9e7332c9e1','4b4f0113-01cf-4dc6-ae1f-30f09e99746b','bb41a88a-ea2b-4830-876d-91fe7f640296','4cb11562-015f-4ab5-969f-0ea8483a0b42']::uuid[], '[{"step":1,"text":"우유에 요거트를 넣어 발효시킨다.","imageUrl":null},{"step":2,"text":"메주콩을 3시간 정도 불린 뒤 불린 콩의 3배의 물을 넣고 삶아\r\n믹서에 간다.","imageUrl":null},{"step":3,"text":"쌀가루와 2번을 섞은 뒤 냄비에 끓여 쌀콩죽을 만든다.","imageUrl":null},{"step":4,"text":"배는 껍질을 제거하고 밥솥에 푹 삶아 믹서에 간다.","imageUrl":null},{"step":5,"text":"고구마는 삶아 껍질을 제거한다.","imageUrl":null},{"step":6,"text":"제조한 요거트(1번)에 쌀콩죽, 배즙, 고구마를 넣고 믹서에 곱게 간다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01131_2.png', 166.5, 22.9, 9.3, 4.2, 8.7),
  ('1132', '상큼하자두', '후식', '자두(100g), 오렌지(170g), 탄산수(100g),
민트잎(5g), 얼음(145g)', '["자두","오렌지","탄산수","민트잎","얼음"]'::jsonb, ARRAY['19eb37dc-2b1c-4e89-a931-31a38ae60561','20a151f5-d44f-48d8-bd67-958886b649d6']::uuid[], '[{"step":1,"text":"자두(30g)를 잘게 다진다.","imageUrl":null},{"step":2,"text":"나머지 자두는 강판에 간다.","imageUrl":null},{"step":3,"text":"오렌지는 즙을 낸다.","imageUrl":null},{"step":4,"text":"오렌지 즙에 1,2번을 넣고 섞는다.","imageUrl":null},{"step":5,"text":"컵에 4번을 넣고 얼음을 넣은 다음 탄산수를 붓는다.","imageUrl":null},{"step":6,"text":"민트잎을 올린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01132_2.png', 40.4, 9, 0.7, 0.1, 4.9),
  ('1133', '비트두유', '후식', '비트(15g), 무첨가두유(200g),
타가토스(5g)', '["비트","무첨가두유","타가토스"]'::jsonb, ARRAY['524e1b82-1f81-4648-b50c-441404a06786']::uuid[], '[{"step":1,"text":"비트를 흐르는 물에 깨끗이 씻는다.","imageUrl":null},{"step":2,"text":"비트를 작게 깍뚝썰기한다","imageUrl":null},{"step":3,"text":"두유에 타가토스를 넣고 완전히 녹도록 섞는다.","imageUrl":null},{"step":4,"text":"잘라둔 비트와 3번을 믹서에 넣고 곱게 간다.","imageUrl":null},{"step":5,"text":"딸기우유 정도의 색이 날 때 까지 간다.","imageUrl":null},{"step":6,"text":"체에 걸러 건더기가 없이한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01133_2.png', 139.6, 10.2, 7.4, 7.7, 7),
  ('1134', '렌틸콩 두유', '후식', '렌틸콩(레드, 70g), 우유(150g),
레몬(1/2개), 딸기(130g), 꿀(15g),
판젤라틴(1.5g), 설탕(3g)', '["렌틸콩","우유","레몬","딸기","꿀","판젤라틴","설탕"]'::jsonb, ARRAY['f82b8382-3b65-4839-9f45-524168f3da07','e937397f-54e2-49df-997a-f393c58360be','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','60a7c3e6-e703-4fb0-b5d9-0119a5deab83','286d1783-cd34-4aae-ac8b-006529ec8bc5','e1ee1919-9a32-462f-ae14-55c7a47ce0a0','06e6f3e7-0293-469d-a338-11a610f3e71b']::uuid[], '[{"step":1,"text":"렌틸콩을 삶아 믹서에 간다.","imageUrl":null},{"step":2,"text":"딸기(100g)를 믹서에 갈고 1번, 우유, 꿀, 레몬즙을 넣고 섞는다.","imageUrl":null},{"step":3,"text":"젤라틴을 물에 담궈 불린다.","imageUrl":null},{"step":4,"text":"딸기를 믹서에 갈아 퓨레를 만들고 설탕을 넣고 끓인다.","imageUrl":null},{"step":5,"text":"4번을 식힌 뒤 젤라틴을 넣고 틀에 넣어 냉동실에서 굳힌다.","imageUrl":null},{"step":6,"text":"2번을 컵에 담고 위에 딸기젤리를 올린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01134_2.png', 87.5, 16.4, 5.3, 0.1, 14.8),
  ('1135', '군고구마 라떼', '후식', '고구마(100g), 우유(200g), 고구마칩(5g)', '["고구마","우유","고구마칩"]'::jsonb, ARRAY['4b4f0113-01cf-4dc6-ae1f-30f09e99746b','e937397f-54e2-49df-997a-f393c58360be']::uuid[], '[{"step":1,"text":"고구마를 쿠킹호일에 싸 직화냄비에 넣고 약한 불에서\r\n30분 간 굽는다.","imageUrl":null},{"step":2,"text":"우유를 냄비에 끓여 데운다.","imageUrl":null},{"step":3,"text":"구운 고구마의 껍질을 제거한다.","imageUrl":null},{"step":4,"text":"우유와 고구마를 믹서에 넣고 간다.","imageUrl":null},{"step":5,"text":"4번을 체에 걸러 부드럽게 한다.","imageUrl":null},{"step":6,"text":"컵에 담고 고구마칩을 올린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01135_2.png', 247.2, 39, 6.9, 7.1, 21),
  ('2952', '바지락 미역국', '국&찌개', '바지락 10g, 미역 5g, 저염간장 5g, 마늘 5g, 참기름 2g, 홍고추 2g, 무 10g, 건새우 10g, 대파 5g, 함초가루 3g', '["바지락","미역","저염간장","마늘","참기름","홍고추","무","건새우","대파","함초가루"]'::jsonb, ARRAY['b6047d76-6c94-4757-b1d1-9175aea0c84a','6565cc3a-c3d6-45b5-a7fb-05a3c03015bf','f175019d-5a93-4cd4-aabc-e7e79445f15a','fc6e31ce-388e-45cd-956b-b238b9134eb1','0c0ade94-cfd8-4104-b44c-40e942cac482','30b5d53c-d247-4f04-9b50-c0f728e65cf9','f80c9a7d-1510-44e2-a82b-28b9f684e191','6f10b4ad-53a2-4a07-ba89-19a6b074373d','4b410642-7bf9-45ad-9055-e7d9a34edaa1','2753a03c-9508-458a-9f55-75307de4f7d5']::uuid[], '[{"step":1,"text":"바지락은 해감하고 미역은 20분 동안 불린다.","imageUrl":null},{"step":2,"text":"물에 파, 마늘, 홍고추, 건새우, 무를 넣고 끓여 육수를 만든다.","imageUrl":null},{"step":3,"text":"냄비에 참기름과 미역, 바지락을 넣고 볶은 뒤 저염간장을 넣고 볶는다.","imageUrl":null},{"step":4,"text":"볶은 냄비에 육수를 넣고 끓인다.","imageUrl":null},{"step":5,"text":"함초가루로 간을 맞춘다.","imageUrl":null},{"step":6,"text":"국그릇에 담는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190405/20190405050142_1554451302804.jpg', 53.5, 4.1, 8.01, 0.56, 802.28),
  ('2954', '단호박견과류샐러드', '기타', ' 단호박(25g), 고구마(25g), 아몬드(5g), 호두(5g), 건블루베리(5g), 당근(10g), 우유(15g)
, 올리고당(5g)', '["단호박","고구마","아몬드","호두","건블루베리","당근","우유","올리고당"]'::jsonb, ARRAY['98d652af-a6d6-440c-9653-e22fc5d47d88','4b4f0113-01cf-4dc6-ae1f-30f09e99746b','52ba316f-8e7f-415f-8079-9a9d674c9adf','7651578f-1206-499d-a04c-15f034d4cae2','e38c12a7-43cb-421a-a36e-7ef0d32517fa','e937397f-54e2-49df-997a-f393c58360be','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d']::uuid[], '[{"step":1,"text":"단호박과 고구마는 껍질을 벗긴다","imageUrl":null},{"step":2,"text":"냄비에 우유를 붓고 단호박과 고구마를 넣어 삶는다.","imageUrl":null},{"step":3,"text":"끓인 우유를 식힌 뒤 단호박과 고구마와 함께 믹서에 넣어 간다.","imageUrl":null},{"step":4,"text":"견과류와 건블루베리, 당근을 잘게 썬다.","imageUrl":null},{"step":5,"text":"믹서에 간 우유에 손질한 견과류와 건블루베리, 당근을 넣어 섞는다.","imageUrl":null},{"step":6,"text":"올리고당으로 농도와 간을 맞춰 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309102734_1678325254074.jpg', 150.3, 15.8, 3.9, 8, 17.9),
  ('2955', '함박스테이크&토마토카레소스', '반찬', '소고기(다짐육) 50g, 양송이버섯 5g, 양파 40g, 빵가루 25g, 다진 마늘 5g, 카레가루 15g, 토마토 25g, 당근 15g, 감자 15g, 계란노른자 5g', '["소고기","양송이버섯","양파","빵가루","다진 마늘","카레가루","토마토","당근","감자","계란노른자"]'::jsonb, ARRAY['1c49d1f4-5781-474d-818d-bd7002a4dc0b','48a4fd5a-e4f6-467b-9e3f-445334e0ee04','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','45080597-55fa-42dc-aa65-12d7694e4b7e','fc6e31ce-388e-45cd-956b-b238b9134eb1','495b9f1e-aa3b-4506-9bb8-feb0a493901e','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','e38c12a7-43cb-421a-a36e-7ef0d32517fa','20894da1-739d-4d52-b5fe-4943bd3492d5']::uuid[], '[{"step":1,"text":"양파, 양송이버섯, 당근, 감자, 토마토를 잘게 다진다.","imageUrl":null},{"step":2,"text":"다진 소고기와 다진 양파, 다진 양송이버섯, 다진 마늘, 빵가루, 계란노른자를 넣고 치댄다.","imageUrl":null},{"step":3,"text":"반죽을 70g씩 나눠 스테이크 모양을 만들어 굽는다.","imageUrl":null},{"step":4,"text":"다진 당근, 감자, 양파, 토마토, 마늘과 카레가루를 물에 넣고 끓인다.","imageUrl":null},{"step":5,"text":"카레 소스가 농도가 날 때 까지 끓인다.","imageUrl":null},{"step":6,"text":"스테이크와 카레소스를 곁들여 담는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408092358_1554683038189.jpg', 84.01, 9.69, 6.2, 2.27, 106.88),
  ('2956', '모둠채소 수제피클', '반찬', ' 오이(20g), 파프리카(20g), 적양배추(20g)
, 설탕(15g), 식초(15g), 피클링스파이스(5g), 물(15g)', '["오이","파프리카","적양배추","설탕","식초","피클링스파이스","물"]'::jsonb, ARRAY['9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','5e79d288-1400-4817-bd20-e5e6041821b1','fd4254d4-2691-47e1-9367-c2b820ef8d00','06e6f3e7-0293-469d-a338-11a610f3e71b','6c285c60-022a-4a00-b172-87df97f16a2f','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"오이와 파프리카, 적양배추는 한 입 크기로 썬다.","imageUrl":null},{"step":2,"text":"냄비에 물과 피클물 재료를 넣어 끓인다.","imageUrl":null},{"step":3,"text":"다른 냄비에 물을 끓여, 피클을 담을 용기를 넣어 소독한다.","imageUrl":null},{"step":4,"text":"소독한 용기를 잘 말린 뒤 손질한 채소를 담는다.","imageUrl":null},{"step":5,"text":"피클물이 끓으면 식힌 뒤 용기에 붓는다.","imageUrl":null},{"step":6,"text":"피클을 30분간 숙성해 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309112534_1678328734115.jpg', 24.3, 4.8, 0.4, 0.4, 1.5),
  ('2957', '바지락 맑은국', '국&찌개', '바지락 30g, 팽이버섯 10g, 홍고추 3g, 쑥갓 1g, 청양고추 3g, 무 8g, 대파 5g, 다시마 5g', '["바지락","팽이버섯","홍고추","쑥갓","청양고추","무","대파","다시마"]'::jsonb, ARRAY['b6047d76-6c94-4757-b1d1-9175aea0c84a','cafedf96-06e9-46a2-a6e2-6cf6f6b15e70','30b5d53c-d247-4f04-9b50-c0f728e65cf9','10ccd1c9-12d7-4075-b2cc-bfc87ce891b6','f80c9a7d-1510-44e2-a82b-28b9f684e191','4b410642-7bf9-45ad-9055-e7d9a34edaa1','84032a7e-ec18-44d5-ab30-c7b960ca5ca9']::uuid[], '[{"step":1,"text":"물에 무와 다시마, 대파, 청양고추를 넣고 끓인다.","imageUrl":null},{"step":2,"text":"끓으면 청양고추와 다시마를 건진다.","imageUrl":null},{"step":3,"text":"해감한 바지락을 넣고 끓인다.","imageUrl":null},{"step":4,"text":"팽이버섯 밑둥을 자른다.","imageUrl":null},{"step":5,"text":"3에 팽이버섯을 넣고 끓인다.","imageUrl":null},{"step":6,"text":"고명으로 어슷 썬 홍고추, 쑥갓을 올린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408093830_1554683910807.jpg', 46.89, 7.76, 3.93, 0.02, 359.39),
  ('2958', '일본식 계란말이', '반찬', '계란 150g, 가츠오부시 10g, 다시마 10g, 설탕 5g, 미림 5g', '["계란","가츠오부시","다시마","설탕","미림"]'::jsonb, ARRAY['c7d438a6-34d6-423f-905d-446b839e2f39','84032a7e-ec18-44d5-ab30-c7b960ca5ca9','06e6f3e7-0293-469d-a338-11a610f3e71b','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1']::uuid[], '[{"step":1,"text":"물에 다시마를 넣고 끓인다.","imageUrl":null},{"step":2,"text":"물이 끓어 오르면 다시마를 건진다.","imageUrl":null},{"step":3,"text":"불을 끈 뒤 가츠오부시를 넣고 체에 걸러 육수를 완성한다.","imageUrl":null},{"step":4,"text":"계란을 풀어 채에 내린 뒤 육수와 미림, 설탕을 넣는다.","imageUrl":null},{"step":5,"text":"팬에 기름을 둘러 계란물을 한겹 한겹 만다.","imageUrl":null},{"step":6,"text":"완성된 계란말이는 모양을 잡고 한입크기로 자른다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408094414_1554684254971.jpg', 138.34, 8.67, 9.95, 7.1, 141.1),
  ('2959', '소고기 가라아게, 칠리소스', '반찬', '소고기 70g, 대파 20g, 토마토 20g, 마늘 10g, 계란노른자 25g, 밀가루 20g, 고춧가루 15g, 식초 50g, 설탕 15g, 전분 10g', '["소고기","대파","토마토","마늘","계란노른자","밀가루","고춧가루","식초","설탕","전분"]'::jsonb, ARRAY['1c49d1f4-5781-474d-818d-bd7002a4dc0b','4b410642-7bf9-45ad-9055-e7d9a34edaa1','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','fc6e31ce-388e-45cd-956b-b238b9134eb1','aab3b0b9-d346-4697-a1c8-1b1530153788','84104c49-0af4-4323-a56b-b67002a422d9','6c285c60-022a-4a00-b172-87df97f16a2f','06e6f3e7-0293-469d-a338-11a610f3e71b','6613d1d9-80a2-4ce4-9d3d-647203197e53']::uuid[], '[{"step":1,"text":"소고기는 채썰고 마늘, 대파는 다진 뒤 섞는다.","imageUrl":null},{"step":2,"text":"1에 계란노른자와 밀가루, 물을 섞어 반죽하고 조그만 공 모양으로 만들어 튀긴다.","imageUrl":null},{"step":3,"text":"토마토는 껍질을 제거한 뒤 다지고, 마늘도 다진다.","imageUrl":null},{"step":4,"text":"식초, 설탕, 물을 끓이다가 다진 토마토, 마늘, 고춧가루를 넣어 끓인다.","imageUrl":null},{"step":5,"text":"전분으로 소스의 농도를 맞춘다.","imageUrl":null},{"step":6,"text":"소고기 가라야게에 칠리소스를 곁들인다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408095001_1554684601056.jpg', 200.49, 15.41, 14.66, 8.91, 286.23),
  ('2969', '삼치튀김, 타르타르소스', '반찬', '삼치 50g, 튀김가루 30g, 계란 60g, 마요네즈 15g, 홍고추 2g, 청양고추 2g, 후추 3g, 양파 5g, 레몬즙 20g, 식용유 5g, 물 20g', '["삼치","튀김가루","계란","마요네즈","홍고추","청양고추","후추","양파","레몬즙","식용유","물"]'::jsonb, ARRAY['40ebc656-16c3-42f6-b601-656230d5d160','aab3b0b9-d346-4697-a1c8-1b1530153788','c7d438a6-34d6-423f-905d-446b839e2f39','549c7365-28e9-491f-9040-412558f93a5c','30b5d53c-d247-4f04-9b50-c0f728e65cf9','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','a7a59e81-de3d-4893-b56a-b2218732a25b','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"삼치의 살과 가시를 분리한다.","imageUrl":null},{"step":2,"text":"키친타올로 삼치살의 핏기와 물기를 제거한 뒤 후추와 레몬즙을 뿌려 비린내를 제거한다.","imageUrl":null},{"step":3,"text":"볼에 튀김가루, 계란, 물, 식용유를 섞어 튀김옷을 만든다.","imageUrl":null},{"step":4,"text":"삼치에 튀김옷을 입힌 뒤 170℃ 기름에서 두 번 튀긴다.","imageUrl":null},{"step":5,"text":"삶은 계란, 홍고추, 청양고추, 양파를 다져 볼에 섞은 뒤 마요네즈와 레몬즙을 섞어 소스를 만든다.","imageUrl":null},{"step":6,"text":"삼치 튀김에 타르타르소스를 곁들여 담는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408111442_1554689682742.jpg', 139.65, 2.05, 11.12, 13, 155.03),
  ('2970', '두부해물완자', '반찬', '두부 50g, 오징어 14g, 칵테일 새우 14g, 감자전분 15g, 부침가루 10g, 계란 20g, 꿀 5g, 새우가루 5g, 마늘 2g, 파 2g, 양파 10g, 저염간장 5g', '["두부","오징어","칵테일 새우","감자전분","부침가루","계란","꿀","새우가루","마늘","파","양파","저염간장"]'::jsonb, ARRAY['4566cac5-9166-4c0d-906a-bfc7360f8f5b','4d148f68-08e0-4599-8953-595db492bf23','6f10b4ad-53a2-4a07-ba89-19a6b074373d','6613d1d9-80a2-4ce4-9d3d-647203197e53','aab3b0b9-d346-4697-a1c8-1b1530153788','c7d438a6-34d6-423f-905d-446b839e2f39','286d1783-cd34-4aae-ac8b-006529ec8bc5','fc6e31ce-388e-45cd-956b-b238b9134eb1','4b410642-7bf9-45ad-9055-e7d9a34edaa1','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','f175019d-5a93-4cd4-aabc-e7e79445f15a']::uuid[], '[{"step":1,"text":"두부를 으깨고 오징어와 새우는 잘게 다진다.","imageUrl":null},{"step":2,"text":"볼에 1의 재료와 감자전분을 넣고 섞어 완자모양으로 만든다.","imageUrl":null},{"step":3,"text":"감자전분과 부침가루를 섞어 완자에 묻힌다.","imageUrl":null},{"step":4,"text":"가루를 묻힌 완자에 계란물을 입혀 기름 두른 팬에 굴려가며 익힌다.","imageUrl":null},{"step":5,"text":"마늘과 파를 다진 뒤 새우가루, 꿀, 저염간장을 섞어 소스를 만든다.","imageUrl":null},{"step":6,"text":"양파를 채 썰어 냄비에 소스와 함께 끓인 뒤 전분물을 넣어 농도를 맞추고 완자를 넣는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408112127_1554690087850.jpg', 116.15, 11.17, 6.19, 5.19, 209.76),
  ('2975', '톳나물 두부무침', '반찬', '톳나물 15g, 두부 40g, 천일염 0.1g, 참깨 0.1g, 참기름 0.1g, 마늘 0.1g', '["톳나물","두부","천일염","참깨","참기름","마늘"]'::jsonb, ARRAY['f3f07b4b-1a27-4a6d-be6d-09e58352e063','4566cac5-9166-4c0d-906a-bfc7360f8f5b','2cf0c12b-f248-4012-8f53-303c730a7b3d','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','0c0ade94-cfd8-4104-b44c-40e942cac482','fc6e31ce-388e-45cd-956b-b238b9134eb1']::uuid[], '[{"step":1,"text":"톳나물을 깨끗이 세척한다.","imageUrl":null},{"step":2,"text":"끓는 물에 톳나물을 살짝 데친다.","imageUrl":null},{"step":3,"text":"데친 톳나물의 물기를 제거하고 한 입 크기로 썬다.","imageUrl":null},{"step":4,"text":"두부를 찜기에 넣고 찐 뒤 으깬다.","imageUrl":null},{"step":5,"text":"마늘을 잘게 다진다.","imageUrl":null},{"step":6,"text":"톳나물과 두부를 볼에 담고 나머지 재료들을 섞는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408010349_1554696229438.jpg', 42.18, 0.9, 3.57, 2.7, 39.9),
  ('2996', '퀴노아 팥수프', '기타', '퀴노아 3g, 팥 10g, 무가당 휘핑크림 25g, 무염 버터 10g, 우유 15g, 닭뼈 20g, 밀가루 10g, 양파 10g, 세발나물 10g, 설탕 3g', '["퀴노아","팥","무가당 휘핑크림","무염 버터","우유","닭뼈","밀가루","양파","세발나물","설탕"]'::jsonb, ARRAY['95fb950a-afb7-4a7f-a6b5-9b912d0e6462','7aabd532-361f-4240-aa33-6bfa1be4bc4e','e937397f-54e2-49df-997a-f393c58360be','aab3b0b9-d346-4697-a1c8-1b1530153788','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','06e6f3e7-0293-469d-a338-11a610f3e71b']::uuid[], '[{"step":1,"text":"세발나물을 살짝 데쳐 말린 뒤 가루를 내고 닭뼈를 이용해 육수를 만든다.","imageUrl":null},{"step":2,"text":"퀴노아를 볶아 쓴맛을 제거하고 삶은 팥과 믹서에 곱게 간다.","imageUrl":null},{"step":3,"text":"팬에 버터 일부를 녹인 뒤 밀가루를 넣어 루를 만든다.","imageUrl":null},{"step":4,"text":"양파를 갈아 버터 녹인 냄비에 볶은 뒤 닭육수와 2를 넣어 끓인다.","imageUrl":null},{"step":5,"text":"세발나물가루로 간을 맞추고 향을 낸 뒤 루를 넣어 농도를 맞춘다.","imageUrl":null},{"step":6,"text":"우유와 휘핑을 넣어 고소함을 더하고 설탕을 소량 넣어 간을 한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409045407_1554796447701.jpg', 432.26, 28, 6.36, 32.76, 319.2),
  ('2997', '참치 두부 함박스테이크', '반찬', '캔참치 20g, 두부 20g, 양파 25g, 토마토 15g, 청피망 20g, 당근 10g, 밀가루 7g, 케찹 15g, 표고버섯가루 1g, 후추 0.5g', '["캔참치","두부","양파","토마토","청피망","당근","밀가루","케찹","표고버섯가루","후추"]'::jsonb, ARRAY['4566cac5-9166-4c0d-906a-bfc7360f8f5b','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','df459e6f-3515-45d5-8c9a-9d37b6249379','e38c12a7-43cb-421a-a36e-7ef0d32517fa','aab3b0b9-d346-4697-a1c8-1b1530153788','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"양파, 피망은 반은 다지고 반은 작은 주사위모양으로 썰고 당근은 다진다.","imageUrl":null},{"step":2,"text":"두부는 칼등으로 으깬 뒤 물기를 제거한다.","imageUrl":null},{"step":3,"text":"2에 캔참치, 다진채소, 표고버섯가루, 밀가루, 후추를 넣어 반죽한 뒤 치대 모양을 만든다.","imageUrl":null},{"step":4,"text":"팬에 식용유를 두르고 3을 노릇하게 굽고 1을 볶는다.","imageUrl":null},{"step":5,"text":"토마토는 주사위모양으로 썰어 케찹과 함께 볶아 소스를 만든다.","imageUrl":null},{"step":6,"text":"접시에 스테이크와 볶은 채소를 담고 토마토소스를 곁들인다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409045907_1554796747438.jpg', 240.26, 25.92, 8.89, 11.29, 149.4),
  ('3000', '김치양배추볶음', '반찬', '배추김치 18g, 양배추 15g, 양파 10g, 대파 1g, 간장 0.2g, 보리새우 0.1g, 마늘 0.5g, 흑임자 0.1g, 들기름 2g', '["배추김치","양배추","양파","대파","간장","보리새우","마늘","흑임자","들기름"]'::jsonb, ARRAY['133f214e-50f4-431d-af36-d97f6c9d4f9b','fd4254d4-2691-47e1-9367-c2b820ef8d00','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','4b410642-7bf9-45ad-9055-e7d9a34edaa1','f175019d-5a93-4cd4-aabc-e7e79445f15a','fc6e31ce-388e-45cd-956b-b238b9134eb1','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','f5534afd-2a26-4493-8ec1-fd680dcb3bef']::uuid[], '[{"step":1,"text":"배추김치는 양념을 헹궈내 짠맛을 제거한 뒤 채 썬다.","imageUrl":null},{"step":2,"text":"양배추, 양파는 곱게 채 썰고 대파는 어슷썬다.","imageUrl":null},{"step":3,"text":"보리새우와 마늘은 곱게 간다.","imageUrl":null},{"step":4,"text":"팬에 들기름을 두르고 김치를 볶다가 양배추와 양파를 넣고 볶는다.","imageUrl":null},{"step":5,"text":"양배추의 숨이 죽으면 간장과 3을 넣어 간을 한다.","imageUrl":null},{"step":6,"text":"흑임자를 뿌린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409051446_1554797686842.jpg', 34.24, 2.75, 0.89, 2.19, 159.33),
  ('3002', '돈수육, 해물냉채', '일품', '돼지고기(삼겹살) 100g, 오징어 15g, 새우 15g, 주꾸미 25g, 적파프리카 5g, 황파프리카 5g, 주황파프리카 5g, 양파 5g, 당근 5g, 오이 5g, 대파 10g, 마늘 10g, 생강 10g, 맛술 5g, 식초 5g, 설탕 5g, 겨자가루 5g, 된장 15g, 통후추 15g', '["돼지고기","오징어","새우","주꾸미","적파프리카","황파프리카","주황파프리카","양파","당근","오이","대파","마늘","생강","맛술","식초","설탕","겨자가루","된장","통후추"]'::jsonb, ARRAY['70e914d4-0d03-4202-8b66-81bd8499aa08','4d148f68-08e0-4599-8953-595db492bf23','6f10b4ad-53a2-4a07-ba89-19a6b074373d','c3f77c6a-2dd2-4592-875f-0aa74771d6d0','5e79d288-1400-4817-bd20-e5e6041821b1','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','e38c12a7-43cb-421a-a36e-7ef0d32517fa','9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','4b410642-7bf9-45ad-9055-e7d9a34edaa1','fc6e31ce-388e-45cd-956b-b238b9134eb1','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1','6c285c60-022a-4a00-b172-87df97f16a2f','06e6f3e7-0293-469d-a338-11a610f3e71b','5b59cfae-1277-48af-99a6-833687e2da0b','392236b1-82e9-4e38-bd12-6a53b80bf463','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"냄비에 물, 대파, 생강, 마늘, 통후추, 맛술, 된장을 넣고 끓인다.","imageUrl":null},{"step":2,"text":"1이 끓으면 삼겹살 덩어리를 넣고 35~40분 간 삶는다.","imageUrl":null},{"step":3,"text":"새우, 오징어, 주꾸미는 모양을 내 데치고 파프리카와 오이, 당근, 양파는 가늘게 채 썬다.","imageUrl":null},{"step":4,"text":"겨자가루를 개어 숙성시켜 설탕, 식초로 냉채 소스를 만든 뒤 3을 넣고 무친다.","imageUrl":null},{"step":5,"text":"2의 삽겹살을 모양대로 썬다.","imageUrl":null},{"step":6,"text":"수육과 해물냉채를 담는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409052530_1554798330170.jpg', 131.87, 3.03, 11.62, 8.14, 215.71),
  ('3003', '알록달록화전, 멸치두부전', '반찬', '찹쌀가루 15g, 알비트 5g, 시금치 5g, 두부 10g, 잔멸치 5g, 식용꽃 10g, 쑥갓 10g, 부침가루 10g, 꿀 20g', '["찹쌀가루","알비트","시금치","두부","잔멸치","식용꽃","쑥갓","부침가루","꿀"]'::jsonb, ARRAY['4cb11562-015f-4ab5-969f-0ea8483a0b42','9a7f4da6-531b-4478-89ff-d73beafcad1b','4566cac5-9166-4c0d-906a-bfc7360f8f5b','dd2eee03-8bbf-44ff-8a7f-ed1443986711','10ccd1c9-12d7-4075-b2cc-bfc87ce891b6','aab3b0b9-d346-4697-a1c8-1b1530153788','286d1783-cd34-4aae-ac8b-006529ec8bc5']::uuid[], '[{"step":1,"text":"두부는 살짝 구워 물기를 제거하고 멸치는 설탕과 함께 볶는다.","imageUrl":null},{"step":2,"text":"알비트, 시금치에 약간의 물을 넣고 각각 믹서에 간다.","imageUrl":null},{"step":3,"text":"찹쌀가루를 알비트, 시금치 간 물에 반죽한다.","imageUrl":null},{"step":4,"text":"두부를 으깨 볶은 멸치와 함께 부침가루에 넣고 반죽한다.","imageUrl":null},{"step":5,"text":"식용꽃과 쑥갓을 씻어 물기를 제거한다.","imageUrl":null},{"step":6,"text":"팬에 3과 4를 각각 부치고 식용꽃과 쑥갓으로 장식하고 꿀을 곁들인다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190419/20190419034505_1555656305675.jpg', 147.88, 24.31, 4.67, 3.55, 86.13),
  ('3095', '단호박떡볶이', '반찬', '떡볶이떡 26g, 단호박 14.5 g, 브로콜리 1.6g, 우유 4ml, 생크림 2.6g, 검정깨 0.01g', '["떡볶이떡","단호박","브로콜리","우유","생크림","검정깨"]'::jsonb, ARRAY['af336608-1eeb-4b10-9a3a-1df0ad140ccb','98d652af-a6d6-440c-9653-e22fc5d47d88','9bf64924-ce53-42bb-849e-7294416e95d6','e937397f-54e2-49df-997a-f393c58360be','af187077-b7f6-4b0e-9e99-f844f6359ac2','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc']::uuid[], '[{"step":1,"text":"떡볶이 떡은 물에 넣어 한 개씩 떼어 놓는다.","imageUrl":null},{"step":2,"text":"단호박은 반으로 잘라 쪄서 속만 파낸다.","imageUrl":null},{"step":3,"text":"브로콜리는 데쳐서 작게 썰어 준비해 둔다.","imageUrl":null},{"step":4,"text":"삶은 단호박, 생크림, 우유를 넣고 간다.","imageUrl":null},{"step":5,"text":"④에 물을 넣고 끓이다가 떡과 브로콜리를 넣어 익힌다.","imageUrl":null},{"step":6,"text":"검정깨를 뿌려 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317111752_1584411472208.JPG', 79.6, 16.2, 1.7, 0.9, 72.8),
  ('1136', '배·라임 모히또', '후식', '배(1개), 라임(1개), 탄산수(500g),
애플민트(5g), 스테비아(5g)', '["배","라임","탄산수","애플민트","스테비아"]'::jsonb, ARRAY['eccf67f1-41f0-4a25-b238-6b9e7332c9e1','20a151f5-d44f-48d8-bd67-958886b649d6','eb4621c9-6ade-40ba-966c-32edd1754669','49b48723-2e40-46b0-9588-00f41a6a02c2']::uuid[], '[{"step":1,"text":"라임을 반으로 잘라 즙을 짠다.","imageUrl":null},{"step":2,"text":"라임즙과 배를 믹서에 넣고 간다.","imageUrl":null},{"step":3,"text":"2번에 애플민트와 올리고당,탄산수를 넣고 믹서로 간다.","imageUrl":null},{"step":4,"text":"냉동실에 3번을 넣고 얼린다.","imageUrl":null},{"step":5,"text":"얼린 모히또를 믹서에 갈아 슬러시처럼 만든다.","imageUrl":null},{"step":6,"text":"잔에 담고 애플민트로 장식한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01136_2.png', 102.7, 24.7, 0.8, 0.1, 16.2),
  ('1137', '포도청 보리 수단', '후식', '포도(150g), 보리(10g), 전분(30g),
녹차(티백, 1개), 설탕(10g)', '["포도","보리","전분","녹차","설탕"]'::jsonb, ARRAY['483ecbd5-47a4-4fb5-bfee-852bded6c1dd','2ca24a23-b88d-4b79-a029-a0748b0850ab','6613d1d9-80a2-4ce4-9d3d-647203197e53','06e6f3e7-0293-469d-a338-11a610f3e71b']::uuid[], '[{"step":1,"text":"포도는 껍질과 씨를 제거한 뒤  설탕을 넣고 포도청을 만든다.","imageUrl":null},{"step":2,"text":"찬물에 녹차를 우려낸다.","imageUrl":null},{"step":3,"text":"보리를 깨끗이 씻은 뒤 푹 삶는다.","imageUrl":null},{"step":4,"text":"삶은 보리에 전분을 묻혀 끓는 물에 삶아 건지는 것을 반복한다.","imageUrl":null},{"step":5,"text":"포도청에 우려낸 녹차를 10:1 비율로 넣는다.","imageUrl":null},{"step":6,"text":"보리수단을 넣는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01137_2.png', 88.3, 21.1, 0.5, 0.2, 11.1),
  ('1138', '감자주스', '후식', '감자(400g), 우유(200g), 설탕(10g)', '["감자","우유","설탕"]'::jsonb, ARRAY['20894da1-739d-4d52-b5fe-4943bd3492d5','e937397f-54e2-49df-997a-f393c58360be','06e6f3e7-0293-469d-a338-11a610f3e71b']::uuid[], '[{"step":1,"text":"감자를 깨끗이 씻는다.","imageUrl":null},{"step":2,"text":"냄비에 설탕을 넣고 감자를 삶는다.","imageUrl":null},{"step":3,"text":"삶은 감자의 껍질을 벗긴다.","imageUrl":null},{"step":4,"text":"껍질 벗긴 감자를 우유와 믹서에넣고 간다.","imageUrl":null},{"step":5,"text":"4번을 체에 걸러 부드럽게 만든다.","imageUrl":null},{"step":6,"text":"컵에 담는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01138_2.png', 171.9, 20.5, 7.6, 6.6, 8.4),
  ('2960', '만가닥버섯볶음', '반찬', '만가닥버섯 25g, 게살(크래미) 10g, 적파프리카 10g, 황파프리카 10g, 청피망 10g, 후추 3g, 소금 1g, 간장 1g', '["만가닥버섯","게살","적파프리카","황파프리카","청피망","후추","소금","간장"]'::jsonb, ARRAY['5e79d288-1400-4817-bd20-e5e6041821b1','df459e6f-3515-45d5-8c9a-9d37b6249379','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','2cf0c12b-f248-4012-8f53-303c730a7b3d','f175019d-5a93-4cd4-aabc-e7e79445f15a']::uuid[], '[{"step":1,"text":"만가닥버섯을 한 송이씩 자른다.","imageUrl":null},{"step":2,"text":"청피망, 황, 적파프리카는 채썰고 게살은 길이로 찢는다.","imageUrl":null},{"step":3,"text":"팬에 기름을 두르고 채썬 파프리카와 피망을 볶는다.","imageUrl":null},{"step":4,"text":"3에 손질한 만가닥버섯을 넣고 볶는다.","imageUrl":null},{"step":5,"text":"찢어둔 게살을 넣고 볶다가 소금, 후추로 간을 한다.","imageUrl":null},{"step":6,"text":"간장으로 색을 내고 담는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408101043_1554685843526.jpg', 25.34, 3.31, 1.61, 0.63, 122.77),
  ('2974', '양파홍초절임', '반찬', '양파 80g, 홍초 15g, 간장 0.1g, 설탕 1.5g, 홍고추 1g, 청양고추 1g', '["양파","홍초","간장","설탕","홍고추","청양고추"]'::jsonb, ARRAY['61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','f175019d-5a93-4cd4-aabc-e7e79445f15a','06e6f3e7-0293-469d-a338-11a610f3e71b','30b5d53c-d247-4f04-9b50-c0f728e65cf9']::uuid[], '[{"step":1,"text":"양파는 깨끗이 씻어 한 입 크기로 자른다.","imageUrl":null},{"step":2,"text":"홍고추와 청양고추는 깨끗이 씻어 어슷하게 썬다.","imageUrl":null},{"step":3,"text":"저염간장과 설탕, 홍초를 넣고 끓여 초절임장을 만든다.","imageUrl":null},{"step":4,"text":"초절임장을 뚜껑이 있는 용기에 옮겨 담는다.","imageUrl":null},{"step":5,"text":"초절임장에 양파와 홍고추, 청양고추를 넣는다.","imageUrl":null},{"step":6,"text":"양파홍초절임을 하루정도 숙성시킨다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408114231_1554691351521.jpg', 56.87, 12.64, 0.55, 0.46, 30.64),
  ('3005', '고구마순나물', '반찬', '고구마순 25g, 양파 10g, 된장 10g, 두부 5g, 마늘 10g, 흑임자 5g, 설탕 5g, 식초 5g, 참기름 5g', '["고구마순","양파","된장","두부","마늘","흑임자","설탕","식초","참기름"]'::jsonb, ARRAY['61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','392236b1-82e9-4e38-bd12-6a53b80bf463','4566cac5-9166-4c0d-906a-bfc7360f8f5b','fc6e31ce-388e-45cd-956b-b238b9134eb1','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','06e6f3e7-0293-469d-a338-11a610f3e71b','6c285c60-022a-4a00-b172-87df97f16a2f','0c0ade94-cfd8-4104-b44c-40e942cac482']::uuid[], '[{"step":1,"text":"두부를 데친 뒤 식혀 으깬다.","imageUrl":null},{"step":2,"text":"으깬 두부에 식초, 설탕, 된장을 섞어 양념을 만든다.","imageUrl":null},{"step":3,"text":"손질한 고구마순을 4cm 길이로 썬다.","imageUrl":null},{"step":4,"text":"고구마순을 데친다.","imageUrl":null},{"step":5,"text":"양파를 곱게 채 썬다.","imageUrl":null},{"step":6,"text":"고구마순에 채 썬 양파와 양념, 흑임자을 넣고 무친다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409054715_1554799635774.jpg', 50.18, 2.13, 1.59, 0.72, 94.33),
  ('3006', '저염 겉절이', '반찬', ' 배추(50g), 무(20g), 쪽파(10g), 양파(5g), 다진마늘(5g), 다진생강(5g), 참깨(1g)
, 저염소금(5g), 고춧가루(10g), 설탕(5g), 젓갈(3g)', '["배추","무","쪽파","양파","다진마늘","다진생강","참깨","저염소금","고춧가루","설탕","젓갈"]'::jsonb, ARRAY['e116f85b-0eaa-40cb-8107-df5ec8486ad4','f80c9a7d-1510-44e2-a82b-28b9f684e191','4b410642-7bf9-45ad-9055-e7d9a34edaa1','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','fc6e31ce-388e-45cd-956b-b238b9134eb1','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','2cf0c12b-f248-4012-8f53-303c730a7b3d','84104c49-0af4-4323-a56b-b67002a422d9','06e6f3e7-0293-469d-a338-11a610f3e71b']::uuid[], '[{"step":1,"text":"배추에 세로로 칼집을 낸 뒤 저염소금을 뿌리고, 10분 뒤 씻는다.","imageUrl":null},{"step":2,"text":"무는 깨끗이 손질하여 씻은 뒤 얇게 채 썰고, 쪽파는 4cm 길이로 썰고, 양파는 채 썬다.","imageUrl":null},{"step":3,"text":"볼에 참깨를 제외한 무, 쪽파, 양파, 다진 마늘, 다진 생강과 저염소금을 제외한 양념재료를 넣고 버무려 양념을 만든다.","imageUrl":null},{"step":4,"text":"저염소금에 절여 씻은 배추를 김치 양념에 골고루 버무린다.","imageUrl":null},{"step":5,"text":"참깨를 뿌려 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306035647_1678085807473.jpg', 55.6, 9.2, 2.1, 1.1, 557.3),
  ('3009', '아욱 된장무침', '반찬', '아욱 200g, 된장 15g, 마늘 10g, 저염간장 5g, 참기름 2g, 참깨 1g, 소금 2g', '["아욱","된장","마늘","저염간장","참기름","참깨","소금"]'::jsonb, ARRAY['392236b1-82e9-4e38-bd12-6a53b80bf463','fc6e31ce-388e-45cd-956b-b238b9134eb1','f175019d-5a93-4cd4-aabc-e7e79445f15a','0c0ade94-cfd8-4104-b44c-40e942cac482','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"아욱 줄기 끝부분을 꺽어 손질한다.","imageUrl":null},{"step":2,"text":"손질한 아욱을 소금을 약간 넣은 물에 넣어 치대듯이 주무른다.","imageUrl":null},{"step":3,"text":"끓는 물에 아욱을 삶은 뒤 찬물에 헹궈 물기를 짠다.","imageUrl":null},{"step":4,"text":"아욱을 먹기 좋은 크기로 썬다.","imageUrl":null},{"step":5,"text":"마늘을 곱게 다진다.","imageUrl":null},{"step":6,"text":"아욱에 된장, 다진마늘, 참기름, 저염간장, 깨를 넣고 버무린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190410/20190410114015_1554864015237.jpg', 11.26, 1.16, 0.9, 0.34, 142.6),
  ('3088', '검은콩부추전', '반찬', '검정콩(서리태) 2.7g, 밀가루 5.3g, 부침가루 5.3g, 홍고추 0.25g, 풋고추 0.25g, 당근 1.2g, 부추 5.9g, 깐양파 3.7g, 애호박 5.3g, 달걀 1.0g, 콩기름 2.0g, 국간장 0.4g', '["검정콩","밀가루","부침가루","홍고추","풋고추","당근","부추","깐양파","애호박","달걀","콩기름","국간장"]'::jsonb, ARRAY['aab3b0b9-d346-4697-a1c8-1b1530153788','30b5d53c-d247-4f04-9b50-c0f728e65cf9','e38c12a7-43cb-421a-a36e-7ef0d32517fa','058648c3-fd8e-476d-952f-b15dc67f1877','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','88c94a13-dc8a-4e66-ab19-08fc2ea82c77','c7d438a6-34d6-423f-905d-446b839e2f39','a7a59e81-de3d-4893-b56a-b2218732a25b','f175019d-5a93-4cd4-aabc-e7e79445f15a']::uuid[], '[{"step":1,"text":"부추는 깨끗이 씻어 4~5cm 길이로 썬다.","imageUrl":null},{"step":2,"text":"애호박, 당근, 양파는 가늘게 채썬다.","imageUrl":null},{"step":3,"text":"홍고추, 풋고추는 어슷하게 썬다.","imageUrl":null},{"step":4,"text":"검정콩은 삶아서 거칠게 갈고, 콩을 삶은 물은 보관한다.","imageUrl":null},{"step":5,"text":"모든 재료를 섞고 콩 삶은 물로 반죽 농도를 맞춘다.","imageUrl":null},{"step":6,"text":"1인 분량씩 노릇하게 부친다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313054355_1584089035031.JPG', 62.3, 9.2, 2.8, 1.6, 65.9),
  ('3089', '고사리파전&단감전', '반찬', '고사리 30g, 쪽파 7g, 홍고추 6g, 계란 20g(0.3개), 밀가루 20g, 단감 13g, 물 30ml, 찹쌀가루 15g, 감자전분 50g, 대추 0.1g', '["고사리","쪽파","홍고추","계란","밀가루","단감","물","찹쌀가루","감자전분","대추"]'::jsonb, ARRAY['9fb1e8e8-c9d9-41f1-a478-fccf9a335175','4b410642-7bf9-45ad-9055-e7d9a34edaa1','30b5d53c-d247-4f04-9b50-c0f728e65cf9','c7d438a6-34d6-423f-905d-446b839e2f39','aab3b0b9-d346-4697-a1c8-1b1530153788','2db5cf59-b4ac-4d7b-8e13-68d143e5f34a','94786475-832c-4f97-aab7-bf6fbbe2236b','4cb11562-015f-4ab5-969f-0ea8483a0b42','6613d1d9-80a2-4ce4-9d3d-647203197e53','b371c5d2-f12b-47ee-9a87-26efd09db09d']::uuid[], '[{"step":1,"text":"고사리와 쪽파는 길이를 반으로 자르고, 홍고추는 길이는 살려 길게 썬다.","imageUrl":null},{"step":2,"text":"기름을 두른 팬에 ①을 얹고 밀가루, 계란 푼 반죽을 부워 지져낸다.","imageUrl":null},{"step":3,"text":"단감을 0.4cm 원형으로 썰고 꽃 모양 틀로 찍어낸다.","imageUrl":null},{"step":4,"text":"찹쌀가루에 감자전분물을 넣어 반죽한다.","imageUrl":null},{"step":5,"text":"기름 두른 팬에 반죽을 동그랗게 만든 후 감과 대추 꽃을 얹어 부친다.","imageUrl":null},{"step":6,"text":"단감전과 먹기 좋은 크기로 썬 고사리 파전을 그릇에 담아 완성시킨다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313054649_1584089209268.JPG', 423.3, 73.2, 9.5, 10.3, 59.2),
  ('3090', '바지락매생이전', '반찬', '매생이 30g, 바지락살 10g, 부침가루 5g, 튀김가루 5g, 홍고추 1g, 대두유 12g', '["매생이","바지락살","부침가루","튀김가루","홍고추","대두유"]'::jsonb, ARRAY['b6047d76-6c94-4757-b1d1-9175aea0c84a','aab3b0b9-d346-4697-a1c8-1b1530153788','30b5d53c-d247-4f04-9b50-c0f728e65cf9']::uuid[], '[{"step":1,"text":"매생이와 바지락은 소금기를 없애기 위해 물에 여러 번 헹군다.","imageUrl":null},{"step":2,"text":"튀김가루, 부침가루에 물을 넣고 반죽을 만든다.","imageUrl":null},{"step":3,"text":"매생이를 잘게 다져 반죽에 섞어준다.","imageUrl":null},{"step":4,"text":"팬에 매생이 반죽을 얹고 바지락살을 넣고 노릇하게 구워준다.","imageUrl":null},{"step":5,"text":"구워진 전에 홍고추 고명을 얹어 준다.","imageUrl":null},{"step":6,"text":"그릇에 담아 마무리 한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313055015_1584089415237.JPG', 83.6, 9.1, 2.1, 4.3, 386.1),
  ('3091', '알콩달콩전', '반찬', '병아리콩 10g, 검정콩 10g, 완두콩 10g, 두부 25g, 빨간 파프리카 5g, 찹쌀가루 10g, 밀가루 5g, 소금 0.3g, 물 2ml, 식용유 10g', '["병아리콩","검정콩","완두콩","두부","빨간 파프리카","찹쌀가루","밀가루","소금","물","식용유"]'::jsonb, ARRAY['f82b8382-3b65-4839-9f45-524168f3da07','5fd34bed-4339-4fcc-9221-f082ce6ac652','4566cac5-9166-4c0d-906a-bfc7360f8f5b','4cb11562-015f-4ab5-969f-0ea8483a0b42','aab3b0b9-d346-4697-a1c8-1b1530153788','2cf0c12b-f248-4012-8f53-303c730a7b3d','94786475-832c-4f97-aab7-bf6fbbe2236b','a7a59e81-de3d-4893-b56a-b2218732a25b']::uuid[], '[{"step":1,"text":"파프리카는 콩 크기의 큐브모양으로 썬다.","imageUrl":null},{"step":2,"text":"준비된 콩들은 물에 불린 후, 각각 끓는 물에 삶은 다음 물기를 제거한다.","imageUrl":null},{"step":3,"text":"두부와 삶은 병아리콩을 으깨준다.","imageUrl":null},{"step":4,"text":"③에 밀가루, 찹쌀가루, 소금, 물을 넣어 반죽한다.","imageUrl":null},{"step":5,"text":"반죽에 콩과 파프리카를 섞는다.","imageUrl":null},{"step":6,"text":"팬에 식용유를 두르고, 반죽의 콩들이 잘 보이도록 먹기 좋은 크기로 부친다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317104751_1584409671661.jpg', 175.5, 20.8, 9.6, 6, 304.1),
  ('3092', '계란만두&토마토소스', '반찬', '가지 7g, 당면 5g, 계란 75g(1.5개), 부추 5g, 양파 10g, 식용유 3g, 토마토홀 30g, 월계수잎 1g, 파슬리 1g, 마늘 3g, 함초소금 0.5g, 후추 0.5g', '["가지","당면","계란","부추","양파","식용유","토마토홀","월계수잎","파슬리","마늘","함초소금","후추"]'::jsonb, ARRAY['3e12cf79-2cde-4309-9f7c-4eccce3fde28','b85df3ba-e324-47fa-b25d-d5bb552b8590','c7d438a6-34d6-423f-905d-446b839e2f39','058648c3-fd8e-476d-952f-b15dc67f1877','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','a7a59e81-de3d-4893-b56a-b2218732a25b','043a9631-bb6e-42e6-9673-4943457502fb','4362c386-a37c-44cd-9254-fafd74712a09','fc6e31ce-388e-45cd-956b-b238b9134eb1','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"당면은 물에 불리고, 물에 불린 당면과 가지, 부추, 양파를 다진다.","imageUrl":null},{"step":2,"text":"계란은 잘 풀어 둔다.","imageUrl":null},{"step":3,"text":"계란과 전처리한 야채, 후추를 넣고 골고루 섞는다.","imageUrl":null},{"step":4,"text":"기름 두른 팬에 반죽을 지름이 10cm되는 타원형 모양으로 올리고, 반쯤 익으면 접어 납작 만두 모양을 만든다.","imageUrl":null},{"step":5,"text":"토마토홀, 월계수잎, 함초소금을 끓여 소스를 만든다.","imageUrl":null},{"step":6,"text":"완성된 계란만두에 소스를 끼얹고 파슬리로 장식한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317105129_1584409889495.jpg', 154.1, 12.2, 11.7, 6.5, 681.3),
  ('3093', '통도라지양념구이', '반찬', '통도라지 80g, 배 5g, 다진마늘 3g, 골파 15g, 통깨 3g, 고추장 10g, 간장 7.5g, 참기름 15g, 소금(쓴맛 제거용) 5g', '["통도라지","배","다진마늘","골파","통깨","고추장","간장","참기름","소금"]'::jsonb, ARRAY['eccf67f1-41f0-4a25-b238-6b9e7332c9e1','fc6e31ce-388e-45cd-956b-b238b9134eb1','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','84b8828b-7396-4dcb-a5d6-44e3cd5a8fdb','f175019d-5a93-4cd4-aabc-e7e79445f15a','0c0ade94-cfd8-4104-b44c-40e942cac482','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"통도라지는 세척 후 껍질을 제거한다.","imageUrl":null},{"step":2,"text":"통도라지를 소금물에 담궈 쓴맛을 우려낸 후 물기를 없앤다.","imageUrl":null},{"step":3,"text":"통도라지를 반으로 갈라서 방망이로 두들겨 얇고 넓적하게 만든다.","imageUrl":null},{"step":4,"text":"갈은 배, 다진 마늘, 고추장, 간장, 참기름을 이용하여 양념장을 만든다.","imageUrl":null},{"step":5,"text":"팬에 도라지를 구워 익히다가, 양념장을 발라 약한불에서 다시 굽는다.","imageUrl":null},{"step":6,"text":"골파와 통깨를 뿌려 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317111149_1584411109361.JPG', 84.8, 12, 2.2, 3.1, 263.9),
  ('3094', '삼색계란찜', '반찬', '계란 60g, 시금치 20g, 비트 10g, 우유 20g, 애플민트 1g, 다시마 3g, 소금 0.5g', '["계란","시금치","비트","우유","애플민트","다시마","소금"]'::jsonb, ARRAY['c7d438a6-34d6-423f-905d-446b839e2f39','9a7f4da6-531b-4478-89ff-d73beafcad1b','524e1b82-1f81-4648-b50c-441404a06786','e937397f-54e2-49df-997a-f393c58360be','eb4621c9-6ade-40ba-966c-32edd1754669','84032a7e-ec18-44d5-ab30-c7b960ca5ca9','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"다시마를 물에 씻어 낸 후 찬물에 우려낸다.","imageUrl":null},{"step":2,"text":"시금치와 비트는 다시마 우린물을 넣고 각각 갈아 준다.","imageUrl":null},{"step":3,"text":"계란과 우유를 섞어 계란물을 만든다.","imageUrl":null},{"step":4,"text":"계란물을 3등분 하여 나눠 담아 놓는다.","imageUrl":null},{"step":5,"text":"나눠 놓은 계란물에 시금치, 비트를 각각 섞는다.","imageUrl":null},{"step":6,"text":"3가지 계란물을 순서대로 쪄 내고, 애플민트로 장식한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317111454_1584411294716.JPG', 178.6, 4.5, 17.1, 10.3, 459.1),
  ('3180', '고구마순들깨나물', '반찬', '고구마순 60g, 들깨가루 20g, 다시마 2g, 소금 1g, 참기름 2g', '["고구마순","들깨가루","다시마","소금","참기름"]'::jsonb, ARRAY['184687ba-0cba-4fec-bb21-33fe300c2073','84032a7e-ec18-44d5-ab30-c7b960ca5ca9','2cf0c12b-f248-4012-8f53-303c730a7b3d','0c0ade94-cfd8-4104-b44c-40e942cac482']::uuid[], '[{"step":1,"text":"고구마순을 끓는 물에 삶아 씻어둔다.","imageUrl":null},{"step":2,"text":"물과 다시마를 약불에 10분정도 우려 다시물을 낸다.","imageUrl":null},{"step":3,"text":"고구마순을 팬으로 옮기고 다시물을 넣어 삶는다.","imageUrl":null},{"step":4,"text":"다시물이 반쯤 줄어들면 소금과 들깻가루를 넣는다.","imageUrl":null},{"step":5,"text":"물기가 없게 볶아준 후 참기름을 넣는다.","imageUrl":null},{"step":6,"text":"접시에 담아서 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129101743_1611883063736.JPG', 118.41, 7.28, 5.44, 7.5, 341.91),
  ('3182', '시금치토마토무침', '반찬', '시금치 80g, 방울토마토 30g, 참기름 2g, 참깨 1g, 마늘 1g, 함초가루 1g', '["시금치","방울토마토","참기름","참깨","마늘","함초가루"]'::jsonb, ARRAY['9a7f4da6-531b-4478-89ff-d73beafcad1b','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','0c0ade94-cfd8-4104-b44c-40e942cac482','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','fc6e31ce-388e-45cd-956b-b238b9134eb1','2753a03c-9508-458a-9f55-75307de4f7d5']::uuid[], '[{"step":1,"text":"시금치를 끓는 물에 살짝 데친다.","imageUrl":null},{"step":2,"text":"데친 시금치는 찬물에 헹구어 내고 물기를 짠다.","imageUrl":null},{"step":3,"text":"방울토마토는 끓는 물에 살짝 데쳐 껍질을 제거한다.","imageUrl":null},{"step":4,"text":"껍질을 제거한 방울토마토는 반으로 자른다.","imageUrl":null},{"step":5,"text":"데친 시금치에 토마토, 함초가루, 참기름, 참깨, 마늘을 넣어 무친다.","imageUrl":null},{"step":6,"text":"접시에 담아 완성시킨다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129103147_1611883907986.jpg', 46.98, 4.43, 2.92, 1.95, 36.9),
  ('3183', '바나나미숫가루쉐이크', '후식', '미숫가루 15g, 바나나 50g, 우유 100ml', '["미숫가루","바나나","우유"]'::jsonb, ARRAY['0b0eef9f-2fa0-4eb5-b1c4-5fc82d28a393','1a4b39f8-b581-46dc-bd7e-289cd6160711','e937397f-54e2-49df-997a-f393c58360be']::uuid[], '[{"step":1,"text":"바나나 껍질을 벗긴다.","imageUrl":null},{"step":2,"text":"바나나를 알맞은 크기로 잘라 준비해 둔다.","imageUrl":null},{"step":3,"text":"우유와 미숫가루를 알맞은 양으로 계량한다.","imageUrl":null},{"step":4,"text":"③과 바나나를 믹서기에 넣는다.","imageUrl":null},{"step":5,"text":"건더기가 생기지 않을 정도로 간다.","imageUrl":null},{"step":6,"text":"컵에 담아 완성시킨다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129103756_1611884276239.jpg', 128.76, 23.35, 5.62, 1.43, 40.75),
  ('3185', '배쨈 식빵', '기타', ' 강력분 500g, 인스턴트 이스트 5g, 소금 7g, 달걀 50g(1개), 우유 250g, 포도씨유 50g
 배 1개, 전분물 24g
(토핑재료) 배 1개', '["강력분","인스턴트 이스트","소금","달걀","우유","포도씨유","배","전분물"]'::jsonb, ARRAY['aab3b0b9-d346-4697-a1c8-1b1530153788','2cf0c12b-f248-4012-8f53-303c730a7b3d','c7d438a6-34d6-423f-905d-446b839e2f39','e937397f-54e2-49df-997a-f393c58360be','a7a59e81-de3d-4893-b56a-b2218732a25b','eccf67f1-41f0-4a25-b238-6b9e7332c9e1']::uuid[], '[{"step":1,"text":"(속재료) 배는 껍질을 제거하고 믹서기에 갈아 준 후 체에 걸러 배즙을 만든다. 배즙을 냄비에 넣고 전분과 함께 중불로 20분간 끓여서 배 시럽을 만든다.","imageUrl":null},{"step":2,"text":"(토핑) 배는 1개는 작게 잘라 건조시켜 배 크런치 10g을 만든다.","imageUrl":null},{"step":3,"text":"강력분, 소금, 이스던트 이스트를 잘 섞다가 달걀과 미지근하게 데운 우유, 포도씨유를 조금씩 넣어가며 반죽한다.","imageUrl":null},{"step":4,"text":"완성된 반죽을 1-2시간동안 실온에서 1차 발효 시킨 후, 세 덩어리로 나누어 15분 정도 2차 발효 해준다.","imageUrl":null},{"step":5,"text":"2차 발효를 마친 반죽 세덩어리를 포도씨유가 발린 식빵틀에 나란히 담아서 180도로 예열한 오븐에 30분 정도 굽는다.\r\n★꼬지로 찔렀을 때 반죽이 묻어나지 않으면 다 익은 거예요.\"","imageUrl":null},{"step":6,"text":"구워진 식빵에 배시럽을 바르고 그 위에 건조시켜 만든 배 크런치를 뿌린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129015238_1611895958550.jpg', 303, 50.96, 10.49, 6.43, 4.98),
  ('3186', '사과 견과류 식빵', '기타', ' 강력분 250g, 소금 5g, 드라이이스트 6g, 버터 25g, 달걀 22g, 우유 175g 
 사과 500g (2개), 견과류 15g', '["강력분","소금","드라이이스트","버터","달걀","우유","사과","견과류"]'::jsonb, ARRAY['aab3b0b9-d346-4697-a1c8-1b1530153788','2cf0c12b-f248-4012-8f53-303c730a7b3d','7aabd532-361f-4240-aa33-6bfa1be4bc4e','c7d438a6-34d6-423f-905d-446b839e2f39','e937397f-54e2-49df-997a-f393c58360be','c85a52b9-c3b4-4a76-951c-bb40edeb3adb']::uuid[], '[{"step":1,"text":"(속재료) 사과 1개와 견과류는 다이스하고 사과 1개는 강판에 간 후 냄비에 졸인다.\r\n★ 사과를 졸이면 단 맛이 농축되고, 갈변도 막을 수 있어요.","imageUrl":null},{"step":2,"text":"강력분과 소금, 이스트, 우유, 물을 넣고 반죽하여 어느 정도 글루텐이 형성되면 버터를 넣어 반죽한다.","imageUrl":null},{"step":3,"text":"반죽을 60분 정도 1차 발효하고 분할해 둥글리기 하여 중간 발효한다.","imageUrl":null},{"step":4,"text":"중간발효가 끝난 반죽은 길게 밀어 편 후 졸인 사과와 견과류를 넣어 롤로 말아 30분간 2차 발효한다.","imageUrl":null},{"step":5,"text":"2차 발효한 반죽 위에 계란물을 발라 아랫불160℃, 윗 불180℃의 오븐에 넣고 30분간 굽는다.","imageUrl":null},{"step":6,"text":"5분정도 남았을 때 꺼내 계란물을 한 번 더 발라 아랫불 170℃, 윗불 180℃로 구워 윗면에 색을 내준다.\r\n★ 굽는 중간에 틀을 돌려주면 골고루 구워져요.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129023426_1611898466994.jpg', 269, 44.91, 9.23, 5.84, 6.42),
  ('3187', '카카오 깜빠뉴', '기타', ' 강력분 500g, 소금 8g, 코코아 30g, 버터 38g, 생이스트 8g, 드라이이스트(레드) 4g, 파트 페레멘테 95g, 우유 114ml, 물 236g 

 카카오 닙스 94g, 호두 94g, 건포도 150g', '["강력분","소금","코코아","버터","생이스트","드라이이스트","파트 페레멘테","우유","물","카카오 닙스","호두","건포도"]'::jsonb, ARRAY['aab3b0b9-d346-4697-a1c8-1b1530153788','2cf0c12b-f248-4012-8f53-303c730a7b3d','7aabd532-361f-4240-aa33-6bfa1be4bc4e','e937397f-54e2-49df-997a-f393c58360be','94786475-832c-4f97-aab7-bf6fbbe2236b','7651578f-1206-499d-a04c-15f034d4cae2','1c1e5578-1128-45a4-bcaf-aae79de3639e']::uuid[], '[{"step":1,"text":"버터를 제외한 모든 재료를 넣어 반죽하다가 버터를 넣어 최종까지 믹스한다. 믹스된 반죽에 속재료를 넣어 골고루 섞는다.","imageUrl":null},{"step":2,"text":"1차 발효 30분 후 punch 후 35분 발효 시킨다.\r\n★punch는 가스를 빼는 과정을 얘기해요.","imageUrl":null},{"step":3,"text":"200g 분할 후 중간발효 20분을 한다.","imageUrl":null},{"step":4,"text":"중간 발효된 반죽은 둥글게 성형한다.","imageUrl":null},{"step":5,"text":"스프레이를 뿌린 후 덧가루를 묻혀 50분 동안 2차 발효 한다.","imageUrl":null},{"step":6,"text":"X모양 칼집을 주고 195℃ 12분 스팀 5초로 설정하여 굽는다.\r\n★칼집은 날이 얇은 면도칼 등을 이용하면 좋아요.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129032316_1611901396829.jpg', 304, 50.51, 9.18, 7.22, 11.22),
  ('3191', '곶감 베이글', '기타', ' 통밀가루 200g, 강력밀가루 150g, 인스턴트 드라이 이스트 8g, 사과종 30ml, 물 220ml, 소금 6g, 카놀라유 20g, 레몬 제스트 1개, 곶감 88g', '["통밀가루","강력밀가루","인스턴트 드라이 이스트","사과종","물","소금","카놀라유","레몬 제스트","곶감"]'::jsonb, ARRAY['aab3b0b9-d346-4697-a1c8-1b1530153788','94786475-832c-4f97-aab7-bf6fbbe2236b','2cf0c12b-f248-4012-8f53-303c730a7b3d','a7a59e81-de3d-4893-b56a-b2218732a25b','2db5cf59-b4ac-4d7b-8e13-68d143e5f34a']::uuid[], '[{"step":1,"text":"레몬의 겉껍질로 제스트를 만들고, 곶감은 작은 다이스로 썬다.","imageUrl":null},{"step":2,"text":"물에 만들어 놓은 레몬 제스트와 소금, 이스트, 사과종, 카놀라유를 넣고 섞어준 뒤 통밀가루와, 강력분을 넣고 반죽해 겉표면이 매끄럽고 탄력성을 가질 때 까지 치댄다.","imageUrl":null},{"step":3,"text":"반죽에 비닐을 덮어 40~50℃에서 2배가 부풀 때까지 1차발효하고, 발효가 끝난 반죽은 기포를 빼준 뒤 75g씩 분할해 둥글리기하고 비닐을 씌워 다시 15분간 중간 발효한다.","imageUrl":null},{"step":4,"text":"반죽은 가스를 살짝 빼주고 타원형으로 밀고, 곶감을 올려 삼절 접기한 다음 이음새를 꼬집고 양쪽을 붙여 원형모양으로 성형하여 30분간 2차 발효한다.","imageUrl":null},{"step":5,"text":"발효된 반죽은 끓는 물에 앞, 뒤로 10초간 데쳐내고 팬닝한다.","imageUrl":null},{"step":6,"text":"200도로 예열된 오븐에서 17분간 굽는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129043447_1611905687183.jpg', 285, 55.76, 9.84, 2.55, 8.51),
  ('3192', '단호박크림을 곁들인 브로콜리 베이글', '기타', ' 강력분 225g, 물 40ml, 블루베리 발효원종 550g, 소금 3g, 올리브유 15g, 브로콜리 100g 
 단호박 600g, 생크림 250g', '["강력분","물","블루베리 발효원종","소금","올리브유","브로콜리","단호박","생크림"]'::jsonb, ARRAY['aab3b0b9-d346-4697-a1c8-1b1530153788','94786475-832c-4f97-aab7-bf6fbbe2236b','2cf0c12b-f248-4012-8f53-303c730a7b3d','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','9bf64924-ce53-42bb-849e-7294416e95d6','98d652af-a6d6-440c-9653-e22fc5d47d88','af187077-b7f6-4b0e-9e99-f844f6359ac2']::uuid[], '[{"step":1,"text":"(속재료) 익힌 단호박과 생크림을 믹싱하여 단호박 크림을 만든다.\r\n★ 단호박은 쪄서 사용하는게 좋아요.","imageUrl":null},{"step":2,"text":"브로콜리를 제외한 반죽 재료를 넣고 최종단계까지 믹싱한 후 삶아서 다진 브로콜리를 넣고 섞어준다. 1차 발효를 고온발효로 27℃에서 1시간 발효한다.","imageUrl":null},{"step":3,"text":"130g씩 분할하여 둥글리기 후 중간 발효를 20분간 한다.","imageUrl":null},{"step":4,"text":"반죽을 30cm ~35cm 정도 늘린 후 링 모양으로 정형하여 팬닝한 후 35℃, 85%의 습도 환경에서 60분간 2차 발효 해주고 끓는 물에 양쪽 면을 데친다.","imageUrl":null},{"step":5,"text":"210℃에서 15분간 구워주고 식힘망에서 식힌다.","imageUrl":null},{"step":6,"text":"\"식은 빵을 갈라 단호박 크림을 샌드한다.\r\n★빵이 식은 후 크림을 올려야 녹지 않아요.\"","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129044142_1611906102544.jpg', 242, 37.22, 7.76, 6.93, 0.98),
  ('3225', '어묵 잡채', '일품', '돼지고기(70g), 어묵(100g), 아삭이고추(30g), 빨강 파프리카(25g), 노랑 파프리카(25g), 콩나물(150g), 소금(0.3g), 후춧가루(0.3g), 굴소스(5g), 참기름(1g)', '["돼지고기","어묵","아삭이고추","빨강 파프리카","노랑 파프리카","콩나물","소금","후춧가루","굴소스","참기름"]'::jsonb, ARRAY['70e914d4-0d03-4202-8b66-81bd8499aa08','5e79d288-1400-4817-bd20-e5e6041821b1','2db049b2-f39c-47ba-857f-fa02b3b0c610','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','d7e0d83c-010c-4b63-9ba4-fcd9af7cbac1','0c0ade94-cfd8-4104-b44c-40e942cac482']::uuid[], '[{"step":1,"text":"돼지고기, 어묵, 아삭이고추, 파프리카는 채 썬다.","imageUrl":null},{"step":2,"text":"콩나물은 찬물에 헹궈 체에 밭친다.","imageUrl":null},{"step":3,"text":"채 썬 돼지고기에 밑간을 한다.","imageUrl":null},{"step":4,"text":"중간 불로 달군 팬에 밑간한 돼지고기를 넣어 3분간 볶는다.","imageUrl":null},{"step":5,"text":"채 썬 재료와 어묵을 넣어 5분간 볶는다.","imageUrl":null},{"step":6,"text":"굴소스를 넣어 1~2분간 볶고 참기름을 두른 뒤 고루 섞는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310100338_1615338218715.jpg', 221.9, 16.2, 21.2, 8, 689.5),
  ('3227', '토마토 비빔국수', '일품', '양파(20g), 바질(10g), 삶은 달걀(1개), 쌀국수(100g), 토마토(200g), 고추장(½Ts), 고춧가루(½Ts), 꿀(1Ts)', '["양파","바질","삶은 달걀","쌀국수","토마토","고추장","고춧가루","꿀"]'::jsonb, ARRAY['61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','ba9e5a79-cab3-4af0-942b-0b35fd745150','c7d438a6-34d6-423f-905d-446b839e2f39','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','84b8828b-7396-4dcb-a5d6-44e3cd5a8fdb','84104c49-0af4-4323-a56b-b67002a422d9','286d1783-cd34-4aae-ac8b-006529ec8bc5']::uuid[], '[{"step":1,"text":"양파, 바질은 채 썰고, 삶은 달걀은 반으로 자른다.","imageUrl":null},{"step":2,"text":"채 썬 양파는 찬물에 담가 체에 밭쳐 물기를 제거한다.","imageUrl":null},{"step":3,"text":"믹서에 비빔소스 재료를 넣고 갈아 비빔소스를 만든다.","imageUrl":null},{"step":4,"text":"끓는 물(8컵)에 쌀국수를 넣어 2분 삶아 찬물에 헹궈 체에 밭친다.","imageUrl":null},{"step":5,"text":"그릇에 쌀국수 → 비빔소스 → 양파, 바질 → 달걀 순으로 얹고 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310102052_1615339252330.jpg', 346, 69.7, 9.9, 3, 128.7),
  ('3228', '멸치 전복 저염국수', '일품', '전복(2개), 애호박(20g), 표고버섯(15g), 당근(20g), 달걀지단(흰자, 노른자 각각 1장), 삶은 쌀소면(80g), 식용유(5㎖), 멸치(5g), 황태포(2g), 다시마(3g), 대파(100g), 양파(60g), 통후추(2g), 고춧가루(3g), 저염 간장(5g), 식초(2g), 다진 파(1g), 다진 마늘(1g), 참기름(1g)', '["전복","애호박","표고버섯","당근","달걀지단","삶은 쌀소면","식용유","멸치","황태포","다시마","대파","양파","통후추","고춧가루","저염 간장","식초","다진 파","다진 마늘","참기름"]'::jsonb, ARRAY['5678a9c5-5df5-4a97-8f95-77df12578956','88c94a13-dc8a-4e66-ab19-08fc2ea82c77','66458b1b-c92f-43fa-8eba-e428892ce88a','e38c12a7-43cb-421a-a36e-7ef0d32517fa','c7d438a6-34d6-423f-905d-446b839e2f39','a7a59e81-de3d-4893-b56a-b2218732a25b','dd2eee03-8bbf-44ff-8a7f-ed1443986711','84032a7e-ec18-44d5-ab30-c7b960ca5ca9','4b410642-7bf9-45ad-9055-e7d9a34edaa1','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','84104c49-0af4-4323-a56b-b67002a422d9','f175019d-5a93-4cd4-aabc-e7e79445f15a','6c285c60-022a-4a00-b172-87df97f16a2f','fc6e31ce-388e-45cd-956b-b238b9134eb1','0c0ade94-cfd8-4104-b44c-40e942cac482']::uuid[], '[{"step":1,"text":"약한 불에 멸치와 황태포를 5분간 볶은 뒤 나머지 육수 재료와 물(1L)을 넣어 끓어오르면 30분간 끓이고 체에 밭쳐 거른다.","imageUrl":null},{"step":2,"text":"건진 멸치는 잘게 다지고, 전복은 껍질과 내장을 제거한 뒤 칼집을 넣고, 애호박, 표고버섯, 당근, 달걀지단은 채 썬다.","imageUrl":null},{"step":3,"text":"잘게 다진 멸치에 멸치 양념장 재료를 넣어 멸치 양념장을 만든다.","imageUrl":null},{"step":4,"text":"냄비에 육수를 붓고 약한 불에 손질한 전복을 넣어 5분간 익힌다.","imageUrl":null},{"step":5,"text":"중간 불로 달군 팬에 식용유(5㎖)를 두른 뒤 손질한 채소를 볶는다.","imageUrl":null},{"step":6,"text":"그릇에 삶은 소면 → 볶은 재료 → 익힌 전복 순으로 담고 육수를 붓는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310101237_1615338757971.jpg', 179, 29.9, 8.3, 2.9, 294.2),
  ('2961', '유부초절임', '반찬', '사과 20g, 유부 5g, 양배추 15g, 당근 10g, 설탕 3g, 식초 15g, 오이 15g, 다시마 5g', '["사과","유부","양배추","당근","설탕","식초","오이","다시마"]'::jsonb, ARRAY['c85a52b9-c3b4-4a76-951c-bb40edeb3adb','fd4254d4-2691-47e1-9367-c2b820ef8d00','e38c12a7-43cb-421a-a36e-7ef0d32517fa','06e6f3e7-0293-469d-a338-11a610f3e71b','6c285c60-022a-4a00-b172-87df97f16a2f','9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','84032a7e-ec18-44d5-ab30-c7b960ca5ca9']::uuid[], '[{"step":1,"text":"유부와 다시마를 데친다.","imageUrl":null},{"step":2,"text":"데친 유부의 물기를 짜내고 채썬다.","imageUrl":null},{"step":3,"text":"데친 다시마를 채썬다.","imageUrl":null},{"step":4,"text":"양배추와 당근, 사과, 오이를 채썬다.","imageUrl":null},{"step":5,"text":"설탕과 식초, 후추를 섞어 소스를 만든다.","imageUrl":null},{"step":6,"text":"채썬 재료와 소스를 섞어 버무린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408101724_1554686244336.jpg', 34.32, 6.11, 1.45, 0.46, 4.22),
  ('3007', '토마토 미소 된장국', '국&찌개', '토마토 50g, 두부 30g, 양파 15g, 표고버섯 15g, 멸치 5g, 고추 8g, 대파 3g, 다시마 2g, 미소된장 30g', '["토마토","두부","양파","표고버섯","멸치","고추","대파","다시마","미소된장"]'::jsonb, ARRAY['aa597bcd-596b-4cbe-a2c4-3da0d060cb50','4566cac5-9166-4c0d-906a-bfc7360f8f5b','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','66458b1b-c92f-43fa-8eba-e428892ce88a','dd2eee03-8bbf-44ff-8a7f-ed1443986711','30b5d53c-d247-4f04-9b50-c0f728e65cf9','4b410642-7bf9-45ad-9055-e7d9a34edaa1','84032a7e-ec18-44d5-ab30-c7b960ca5ca9','392236b1-82e9-4e38-bd12-6a53b80bf463']::uuid[], '[{"step":1,"text":"멸치, 다시마를 끓여 육수를 만든다.","imageUrl":null},{"step":2,"text":"두부, 양파, 표고버섯, 고추, 대파를 먹기 좋은 크기로 썬다.","imageUrl":null},{"step":3,"text":"냄비에 물을 끓여 토마토를 5분 정도 익힌다.","imageUrl":null},{"step":4,"text":"토마토 껍질을 제거하고 적당한 크기로 썰어 씨를 제거한다.","imageUrl":null},{"step":5,"text":"육수에 미소 된장을 풀고 양파, 표고버섯을 넣는다.","imageUrl":null},{"step":6,"text":"토마토와 대파를 넣는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409055823_1554800303065.jpg', 46.85, 5.29, 3.43, 1.33, 630.14),
  ('3013', '미역 미소국', '국&찌개', ' 건미역(2g), 가다랑어포(0.3g)
, 미소된장(3g), 미향(0.3g), 물(350g)', '["건미역","가다랑어포","미소된장","미향","물"]'::jsonb, ARRAY['6565cc3a-c3d6-45b5-a7fb-05a3c03015bf','47fc4ccd-d88e-4a88-9b91-e6147e571342','392236b1-82e9-4e38-bd12-6a53b80bf463','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"건미역을 물에 불린다.","imageUrl":null},{"step":2,"text":"불린 미역을 잘게 썬다.","imageUrl":null},{"step":3,"text":"냄비에 물(350g)과 가다랑어포를 넣어 우려내 육수를 만든다.","imageUrl":null},{"step":4,"text":"육수에 미소된장을 곱게 푼다.","imageUrl":null},{"step":5,"text":"국에 미역을 넣어 한소끔 끓인다.","imageUrl":null},{"step":6,"text":"미향을 넣어 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309031437_1678342477922.jpg', 15.1, 2.8, 0.9, 0, 196.8),
  ('3096', '포두부채소잡채', '반찬', ' 포두부(100g), 참느타리버섯(45g), 양파(45g), 게맛살(15g), 청피망(15g), 홍피망(15g), 파(10g), 생강(3g), 식용유(3g)
, 다진마늘(10g), 설탕(15g), 노두유(3g)', '["포두부","참느타리버섯","양파","게맛살","청피망","홍피망","파","생강","식용유","다진마늘","설탕","노두유"]'::jsonb, ARRAY['61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','df459e6f-3515-45d5-8c9a-9d37b6249379','4b410642-7bf9-45ad-9055-e7d9a34edaa1','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','a7a59e81-de3d-4893-b56a-b2218732a25b','fc6e31ce-388e-45cd-956b-b238b9134eb1','06e6f3e7-0293-469d-a338-11a610f3e71b']::uuid[], '[{"step":1,"text":"포두부, 양파, 피망, 파, 생강은 가늘게 채 썬다.","imageUrl":null},{"step":2,"text":"참느타리버섯, 게맛살은 가늘게 찢는다.","imageUrl":null},{"step":3,"text":"냄비에 물을 끓이고 포두부는 미리 데쳐 체에 밭쳐 물기를 뺀다.","imageUrl":null},{"step":4,"text":"팬에 식용유를 두른 뒤 파, 다진 마늘, 생강을 볶는다.","imageUrl":null},{"step":5,"text":"손질한 채소와 참느타리버섯, 게맛살을 넣어 볶는다.","imageUrl":null},{"step":6,"text":"채소가 익으면 데쳐 놓은 포두부를 넣고 볶다가 노두유와 설탕으로 간을 해 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308054041_1678264841984.jpg', 289, 17.5, 22.2, 14.5, 308.2),
  ('3196', '속이 든든든한 밥 빵', '기타', ' 강력 쌀가루 240g, 불린밥 100g, 물 150ml, 이스트 4g, 소금 4g, 코코넛 오일 12g 
 단호박 700g, 옥수수 100g', '["강력 쌀가루","불린밥","물","이스트","소금","코코넛 오일","단호박","옥수수"]'::jsonb, ARRAY['94786475-832c-4f97-aab7-bf6fbbe2236b','325279ee-6de6-4d84-96a0-16af87dfdbc6','2cf0c12b-f248-4012-8f53-303c730a7b3d','98d652af-a6d6-440c-9653-e22fc5d47d88','75ae0b33-6449-4b14-a6b8-bebe016d5b33']::uuid[], '[{"step":1,"text":"(속재료) 익혀 낸 단호박과 옥수수 알을 섞어준다.","imageUrl":null},{"step":2,"text":"쌀가루, 소금, 불린 밥, 물을 넣고 한 덩어리가 되게 반죽한 다음 코코넛 오일을 넣고 부드러워질 때까지 반죽한다.","imageUrl":null},{"step":3,"text":"\"반죽의 크기가 두 배가 될 때까지 발효한다. \r\n★손으로 반죽을 눌렀을 때 자국이 남아 있으면 발효가 잘 된 거예요.\"","imageUrl":null},{"step":4,"text":"반죽을 얇은 직사각형(크기 약 35cm ×28cm, 두께 약 0.5cm )으로 밀어 위에 속재료를 바르고 말아준다.","imageUrl":null},{"step":5,"text":"말린 반죽을 약 4cm 크기로 잘라 머핀틀에 넣어 틀에 꽉 찰때까지 발효한다.","imageUrl":null},{"step":6,"text":"위에 우유를 발라 윗불 180℃, 아랫불 160℃ 예열된 오븐에 20~25분 굽는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129055906_1611910746844.jpg', 228, 41.59, 8.52, 3.06, 5.35),
  ('3230', '참외지 리코타버무리', '후식', '참외(110g), 아몬드(5g), 소금(1g), 설탕(2g), 레몬즙(15g), 올리브유(2g), 유자청(5g), 리코타치즈(15g)', '["참외","아몬드","소금","설탕","레몬즙","올리브유","유자청","리코타치즈"]'::jsonb, ARRAY['7dd9d8bc-46ee-40cb-974c-6fb77702e323','52ba316f-8e7f-415f-8079-9a9d674c9adf','2cf0c12b-f248-4012-8f53-303c730a7b3d','06e6f3e7-0293-469d-a338-11a610f3e71b','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','ff5b6cbe-7985-4ca2-94ad-5525717cddf1']::uuid[], '[{"step":1,"text":"참외는 껍질을 벗기고 반 갈라 속을 파내고, 파낸 속은 면포에 감싸 즙을 짠다.","imageUrl":null},{"step":2,"text":"과육은 필러로 얇게 저민 뒤 손으로 즙을 꼭 짠다.","imageUrl":null},{"step":3,"text":"참외즙에 끓는 물(50㎖)과 양념을 넣어 고루 섞는다.","imageUrl":null},{"step":4,"text":"양념을 섞은 참외즙에 얇게 저민 참외 과육을 넣어 냉장실에서 20분간 절인다.","imageUrl":null},{"step":5,"text":"소스를 만든다.","imageUrl":null},{"step":6,"text":"절인 참외 과육을 찬물에 헹궈 물기를 꼭 짠 뒤 그릇에 담고 소스와 아몬드를 곁들인다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20221208/20221208044333_1670485413793.jpg', 203.9, 16.3, 5.4, 13, 100.3),
  ('3231', '과일 피클 젤리', '후식', '방울토마토(50g), 바나나(80g), 청포도(50g), 젤라틴(7.5g), 한천가루(0.25g), 피클링 스파이스(5g), 사과식초(10g), 설탕(3g), 올리고당(5g), 소금(1g)', '["방울토마토","바나나","청포도","젤라틴","한천가루","피클링 스파이스","사과식초","설탕","올리고당","소금"]'::jsonb, ARRAY['aa597bcd-596b-4cbe-a2c4-3da0d060cb50','1a4b39f8-b581-46dc-bd7e-289cd6160711','483ecbd5-47a4-4fb5-bfee-852bded6c1dd','e1ee1919-9a32-462f-ae14-55c7a47ce0a0','6c285c60-022a-4a00-b172-87df97f16a2f','06e6f3e7-0293-469d-a338-11a610f3e71b','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"과일은 한입 크기로 썬다.","imageUrl":null},{"step":2,"text":"젤라틴은 찬물에 불린다.","imageUrl":null},{"step":3,"text":"냄비에 물(100㎖), 양념을 넣어 끓인 뒤 피클링 스파이스를 체로 거른다.","imageUrl":null},{"step":4,"text":"③에 불린 젤라틴과 한천가루를 넣어 녹인 뒤 한 김 식힌다.","imageUrl":null},{"step":5,"text":"유리 용기에 손질한 과일을 담고 식힌 ④의 젤라틴 물을 붓는다.","imageUrl":null},{"step":6,"text":"냉장실에서 1시간 30분간 굳혀 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20221208/20221208043833_1670485113169.jpg', 78.9, 14.5, 4.7, 0.2, 169.5),
  ('3232', '바나나 쑥두부푸딩', '후식', '흰강낭콩(30g), 두부(140g), 우유(40g), 올리고당(50g), 바나나(1개), 쑥 파우더(1g), 아몬드(2g)', '["흰강낭콩","두부","우유","올리고당","바나나","쑥 파우더","아몬드"]'::jsonb, ARRAY['4566cac5-9166-4c0d-906a-bfc7360f8f5b','e937397f-54e2-49df-997a-f393c58360be','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d','1a4b39f8-b581-46dc-bd7e-289cd6160711','52ba316f-8e7f-415f-8079-9a9d674c9adf']::uuid[], '[{"step":1,"text":"흰강낭콩은 물에 담가 8시간 불렸다가 건진 뒤 끓는 물에 20분간 삶는다.","imageUrl":null},{"step":2,"text":"끓는 물에 두부를 살짝 데쳐 건진다.","imageUrl":null},{"step":3,"text":"믹서에 데친 두부, 삶은 흰강낭콩, 우유, 올리고당, 바나나(½분량)를 넣어 곱게 간다.","imageUrl":null},{"step":4,"text":"믹서에 데친 두부, 삶은 흰강낭콩, 우유, 올리고당, 바나나(½분량)를 넣어 곱게 간다.","imageUrl":null},{"step":5,"text":"나머지 바나나는 한입 크기로 썰고 아몬드와 함께 푸딩 위에 올린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20221208/20221208043901_1670485141626.jpg', 482.8, 61.7, 22.4, 16.3, 70.6),
  ('3233', '채소말이와 고구마가지구이', '일품', '가지(½개+20g), 양배추(70g), 빨강 파프리카(20g), 당근(20g), 청경채(1단), 달걀지단(3개 분량), 구운 김(1장), 불린 라이스페이퍼(2장), 깻잎(2장), 찐 고구마(200g), 우유(15g), 무염 버터(20g), 다진 마늘(5g), 무염 치즈(15g), 생크림(75g), 후춧가루(0.5g), 식용 꽃(노란색 2개), 파슬리가루(2g), 식용유(35ml)', '["가지","양배추","빨강 파프리카","당근","청경채","달걀지단","구운 김","불린 라이스페이퍼","깻잎","찐 고구마","우유","무염 버터","다진 마늘","무염 치즈","생크림","후춧가루","식용 꽃","파슬리가루","식용유"]'::jsonb, ARRAY['3e12cf79-2cde-4309-9f7c-4eccce3fde28','fd4254d4-2691-47e1-9367-c2b820ef8d00','5e79d288-1400-4817-bd20-e5e6041821b1','e38c12a7-43cb-421a-a36e-7ef0d32517fa','7ac59c14-e767-4f32-a2e5-d558c1a29dfb','c7d438a6-34d6-423f-905d-446b839e2f39','09229cbc-4574-4002-b726-68c37345bbe9','3c38eb1c-6ef4-4bb8-82be-74f679ce9e91','e937397f-54e2-49df-997a-f393c58360be','7aabd532-361f-4240-aa33-6bfa1be4bc4e','fc6e31ce-388e-45cd-956b-b238b9134eb1','af187077-b7f6-4b0e-9e99-f844f6359ac2','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','4362c386-a37c-44cd-9254-fafd74712a09','a7a59e81-de3d-4893-b56a-b2218732a25b']::uuid[], '[{"step":1,"text":"가지(½개)는 반 갈라 속을 파고, 나머지 가지(20g), 양배추(50g), 빨강 파프리카, 당근은 채 썰고, 양배추(20g)와 청경채는 한입 크기로 썰고, 달걀지단은 채 썬다.","imageUrl":null},{"step":2,"text":"찐 고구마는 껍질을 벗겨 우유와 생크림, 무염 버터를 으깨고 고루 섞어 속을 판 가지에 채운 뒤 다진 마늘과 무염 치즈를 올려 180℃로 예열한 오븐에 5분간 굽는다.","imageUrl":null},{"step":3,"text":"중간 불로 달군 팬에 식용유(20㎖)를 두른 뒤 채 썬 가지, 양배추, 파프리카, 당근을 2분간 볶아 꺼낸다.","imageUrl":null},{"step":4,"text":"같은 팬에 식용유(15㎖)를 두른 뒤 한입 크기로 썬 양배추와 청경채, 후춧가루(0.5g)를 넣어 3분간 볶아 꺼낸다.","imageUrl":null},{"step":5,"text":"구운 김에 불린 라이스페이퍼 → 달걀지단 → 깻잎 → 볶은 채 썬 채소 순으로 넣어 돌돌 말아 한입 크기로 썬다.","imageUrl":null},{"step":6,"text":"그릇에 구운 가지 → 볶은 양배추와 청경채 → 김밥 순으로 올리고 꽃잎과 파슬리가루(2g)를 뿌려 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310023755_1615354675351.jpg', 548.4, 58.3, 15.9, 28, 229.8),
  ('3234', '들깨 곤약 냉채', '일품', '닭가슴살(40g), 노랑 파프리카(20g), 양파(15g), 오이(15g), 당근(15g), 곤약면(80g), 어린잎채소(10g), 겨잣가루(10g), 식초(20g), 올리고당(10g), 들깻가루(10g), 소금(0.3g), 저염 간장(0.5g)', '["닭가슴살","노랑 파프리카","양파","오이","당근","곤약면","어린잎채소","겨잣가루","식초","올리고당","들깻가루","소금","저염 간장"]'::jsonb, ARRAY['e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','5e79d288-1400-4817-bd20-e5e6041821b1','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','e38c12a7-43cb-421a-a36e-7ef0d32517fa','bc0ebb76-798a-40fe-be99-557ca2b9a9b4','6c285c60-022a-4a00-b172-87df97f16a2f','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d','184687ba-0cba-4fec-bb21-33fe300c2073','2cf0c12b-f248-4012-8f53-303c730a7b3d','f175019d-5a93-4cd4-aabc-e7e79445f15a']::uuid[], '[{"step":1,"text":"닭가슴살은 끓는 물에 7분간 삶아 건진 뒤 결대로 찢어 준비한다.","imageUrl":null},{"step":2,"text":"노랑 파프리카, 양파, 오이, 당근은 채 썬다.","imageUrl":null},{"step":3,"text":"곤약면은 끓는 물에 살짝 데쳐 건진 뒤 찬물에 씻어 체에 밭쳐 물기를 제거한다.","imageUrl":null},{"step":4,"text":"들깨소스를 만든다.","imageUrl":null},{"step":5,"text":"곤약면에 삶은 닭가슴살, 채 썬 채소, 들깨소스를 넣어 버무린다.","imageUrl":null},{"step":6,"text":"그릇에 담고 어린잎채소를 올린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310035228_1615359148382.jpg', 124, 10.2, 14.3, 2.9, 55.2),
  ('3236', '요거트 단호박 샐러드', '일품', '단호박(100g), 감자(5g), 표고버섯(5g), 불린 곤드레나물(10g), 불린 쌀(30g), 건포도(5g), 건무화과(5g), 볶은 호두(5g), 볶은 아몬드 슬라이스(5g), 라즈베리(5g), 요거트(20g)', '["단호박","감자","표고버섯","불린 곤드레나물","불린 쌀","건포도","건무화과","볶은 호두","볶은 아몬드 슬라이스","라즈베리","요거트"]'::jsonb, ARRAY['98d652af-a6d6-440c-9653-e22fc5d47d88','20894da1-739d-4d52-b5fe-4943bd3492d5','66458b1b-c92f-43fa-8eba-e428892ce88a','a5bc0b46-0192-496a-b429-d2cb90b2bca9','1c1e5578-1128-45a4-bcaf-aae79de3639e','7651578f-1206-499d-a04c-15f034d4cae2','52ba316f-8e7f-415f-8079-9a9d674c9adf','bb41a88a-ea2b-4830-876d-91fe7f640296']::uuid[], '[{"step":1,"text":"단호박은 껍질을 벗겨 찜기에 넣어 5분간 찐 뒤 으깬다.","imageUrl":null},{"step":2,"text":"감자와 표고버섯은 채 썰고, 불린 곤드레나물은 잘게 썬다.","imageUrl":null},{"step":3,"text":"냄비에 불린 쌀, 채 썬 감자와 표고버섯, 불린 곤드레나물, 물(20㎖)을 넣어 센 불로 5분 30초간 끓인다.","imageUrl":null},{"step":4,"text":"오븐 팬에 감자곤드레밥을 얇게 편 뒤 180℃로 예열한 오븐에 구워 누룽지를 만든다.","imageUrl":null},{"step":5,"text":"으깬 단호박에 건과일과 볶은 호두, 볶은 아몬드 슬라이스를 넣어 고루 섞는다.","imageUrl":null},{"step":6,"text":"그릇에 건과일과 견과류를 섞은 단호박을 예쁘게 담고 곤드레 누룽지와 라즈베리, 요거트를 올린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20221208/20221208044231_1670485351624.jpg', 270.6, 48.1, 8.5, 4.9, 36.2),
  ('3286', '타이거새우 현미볶음밥', '밥', ' 브로콜리(¼개), 양파(¼개), 파프리카(빨강, 노랑 각 ¼개), 쪽파(2대), 블랙타이거새우(8마리), 현미밥(2공기), 청양고추(2개), 레몬(½개), 다진 마늘(3Ts), 버터(3Ts)', '["브로콜리","양파","파프리카","쪽파","블랙타이거새우","현미밥","청양고추","레몬","다진 마늘","버터"]'::jsonb, ARRAY['9bf64924-ce53-42bb-849e-7294416e95d6','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','5e79d288-1400-4817-bd20-e5e6041821b1','4b410642-7bf9-45ad-9055-e7d9a34edaa1','30b5d53c-d247-4f04-9b50-c0f728e65cf9','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','fc6e31ce-388e-45cd-956b-b238b9134eb1','7aabd532-361f-4240-aa33-6bfa1be4bc4e']::uuid[], '[{"step":1,"text":"브로콜리는 윗동만 분리해 다지고, 양파, 파프리카, 청양고추는 잘게 다지고, 쪽파는 송송 썰고, 레몬은 2등분한다.","imageUrl":null},{"step":2,"text":"블랙타이거새우는 깨끗하게 씻은 뒤 머리를 제거한다.","imageUrl":null},{"step":3,"text":"약한 불로 달군 팬에 식용유를 두르고, 다진 마늘을 넣어 튀기듯 볶은 뒤 양파를 넣어 볶는다.","imageUrl":null},{"step":4,"text":"손질한 블랙타이거새우와 버터를 넣은 뒤 새우의 색이 변할 때까지 볶고, 다진 파프리카, 청양고추, 브로콜리를 넣어 2분간 볶는다.","imageUrl":null},{"step":5,"text":"그릇에 현미밥을 담고, 볶은 블랙타이거 새우와 국물을 골고루 뿌린다.","imageUrl":null},{"step":6,"text":"송송 썬 쪽파와 레몬을 올려 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr98sn', 536.9, 44.8, 31.9, 25.6, 318.3),
  ('3289', '카레크림 두부면 파스타', '기타', ' 콜리플라워(200g), 양송이버섯(2개), 양파(½개), 마늘(3쪽), 무가당 두유(2컵), 두부면(1팩=100g), 바질(3장), 올리브유(1Ts), 다진 마늘(1ts), 강황가루(2Ts), 식초(1ts), 파슬리가루(1ts)', '["콜리플라워","양송이버섯","양파","마늘","무가당 두유","두부면","바질","올리브유","다진 마늘","강황가루","식초","파슬리가루"]'::jsonb, ARRAY['4268226c-9999-4a22-8477-03127720f26f','48a4fd5a-e4f6-467b-9e3f-445334e0ee04','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','fc6e31ce-388e-45cd-956b-b238b9134eb1','ba9e5a79-cab3-4af0-942b-0b35fd745150','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','a7cf6fb8-b34f-4cfe-a4af-d8e000090dcb','6c285c60-022a-4a00-b172-87df97f16a2f','4362c386-a37c-44cd-9254-fafd74712a09']::uuid[], '[{"step":1,"text":"콜리플라워는 잘게 썰고, 양송이버섯과 양파는 3mm 두께로 채 썰고, 마늘(2쪽)은 납작 썬다.","imageUrl":null},{"step":2,"text":"믹서에 잘게 썬 콜리플라워, 무가당 두유, 물(1컵), 마늘(1쪽)을 넣어 곱게 갈아 콜리플라워 크림을 만든다.","imageUrl":null},{"step":3,"text":"중간 불로 달군 팬에 올리브유를 두른 뒤 다진 마늘을 볶고, 납작 썬 마늘, 양파, 양송이버섯을 넣어 양파가 숨이 죽을 때까지 볶는다.","imageUrl":null},{"step":4,"text":"콜리플라워 크림을 넣은 뒤 끓어오르면 강황가루와 두부면을 넣어 골고루 섞는다.","imageUrl":null},{"step":5,"text":"바질을 넣어 고루 섞고, 불을 끈 뒤 식초를 넣어 고루 섞는다.","imageUrl":null},{"step":6,"text":"그릇에 카레크림 두부면 파스타를 담고, 파슬리가루를 뿌려 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9AyL', 197.7, 9.8, 16.2, 10.4, 66.2),
  ('2962', '홍합 배춧국', '국&찌개', '홍합 50g, 배추 50g, 무 30g, 마늘 2g, 파 3g, 홍고추 1g, 소금 0.3g', '["홍합","배추","무","마늘","파","홍고추","소금"]'::jsonb, ARRAY['1ddd4301-779b-4e99-a008-4933509afaf7','e116f85b-0eaa-40cb-8107-df5ec8486ad4','f80c9a7d-1510-44e2-a82b-28b9f684e191','fc6e31ce-388e-45cd-956b-b238b9134eb1','4b410642-7bf9-45ad-9055-e7d9a34edaa1','30b5d53c-d247-4f04-9b50-c0f728e65cf9','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"끓는 물에 한 입 크기로 썬 무를 넣는다.","imageUrl":null},{"step":2,"text":"무가 투명해지면 배추를 넣고 끓인다.","imageUrl":null},{"step":3,"text":"홍합을 넣는다.","imageUrl":null},{"step":4,"text":"홍합이 입을 벌리면 마늘을 다져 넣어 조미한다.","imageUrl":null},{"step":5,"text":"소금을 넣는다.","imageUrl":null},{"step":6,"text":"어슷 썬 파와 홍고추를 고명으로 올린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408102339_1554686619522.jpg', 23.07, 2.14, 2.01, 0.72, 60.48),
  ('2977', '얼큰 콩나물 수제비', '일품', '콩나물 50g, 황태머리 40g, 고추장 10g, 밀가루 100g, 고춧가루 5g, 소금 2g', '["콩나물","황태머리","고추장","밀가루","고춧가루","소금"]'::jsonb, ARRAY['2db049b2-f39c-47ba-857f-fa02b3b0c610','84b8828b-7396-4dcb-a5d6-44e3cd5a8fdb','aab3b0b9-d346-4697-a1c8-1b1530153788','84104c49-0af4-4323-a56b-b67002a422d9','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"밀가루에 소금을 섞어 반죽한 뒤 숙성시킨다.","imageUrl":null},{"step":2,"text":"황태머리를 구운 뒤 찬물에 넣고 끓여 육수를 만들어 거즈에 거른다.","imageUrl":null},{"step":3,"text":"냄비에 2의 육수를 붓고 콩나물 1/2를 넣은 뒤 끓어 오르면 고추장과 고춧가루를 풀어 끓인다.","imageUrl":null},{"step":4,"text":"숙성된 수제비 반죽을 밀어 따로 끓인 물에 삶아 건진다.","imageUrl":null},{"step":5,"text":"3에 4의 수제비를 넣고 한소끔 끓인다.","imageUrl":null},{"step":6,"text":"나머지 콩나물을 넣어 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408011347_1554696827859.jpg', 228.82, 47.95, 9.06, 0.09, 466.2),
  ('3008', '단호박 생선탕수, 키위소스', '반찬', '동태살 120g, 단호박 10g, 당근 15g, 오이 15g, 양파 15g, 전분 30g, 계란 110g, 튀김가루 10g, 목이버섯 3g, 식초 15g, 키위소스 20g', '["동태살","단호박","당근","오이","양파","전분","계란","튀김가루","목이버섯","식초","키위소스"]'::jsonb, ARRAY['98d652af-a6d6-440c-9653-e22fc5d47d88','e38c12a7-43cb-421a-a36e-7ef0d32517fa','9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','6613d1d9-80a2-4ce4-9d3d-647203197e53','c7d438a6-34d6-423f-905d-446b839e2f39','aab3b0b9-d346-4697-a1c8-1b1530153788','aad7c333-f1f0-46c1-8313-37cc64d689dc','6c285c60-022a-4a00-b172-87df97f16a2f']::uuid[], '[{"step":1,"text":"따뜻한 물에 부린 목이버섯, 동태살, 당근, 오이, 양파를 먹기 좋은 크기로 썬다.","imageUrl":null},{"step":2,"text":"동태살에 소금과 흰후추로 밑간을 하고 녹말과 계란 흰자를 섞어 튀김옷을 만든다.","imageUrl":null},{"step":3,"text":"동태살에 튀김옷을 입혀 기름에 튀긴다.","imageUrl":null},{"step":4,"text":"물, 계란, 튀김가루를 섞어 튀김옷을 만든 뒤 단호박을 튀긴다.","imageUrl":null},{"step":5,"text":"프라이팬에 기름을 두르고 당근, 양파, 목이버섯을 볶는다.","imageUrl":null},{"step":6,"text":"5에 키위소스, 식초를 넣고 전분물을 넣어 농도를 맞춘 뒤 튀긴 재료와 오이를 섞는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190410/20190410113325_1554863605497.jpg', 116.56, 13.68, 3.85, 5.16, 140.65),
  ('3097', '낙지모듬초말이', '반찬', '낙지 30g, 가지 12g, 오이 7g, 표고버섯 24g, 당근 10g, 미나리 12g, 홍고추 0.1g, 설탕 15g, 식초 25g, 물 30m , 사과 10g, 간장10g, 고춧가루 1g, 깨 1g', '["낙지","가지","오이","표고버섯","당근","미나리","홍고추","설탕","식초","물","사과","간장","고춧가루","깨"]'::jsonb, ARRAY['bd61e0e7-ed60-47e9-9a29-95dcc8ca68af','3e12cf79-2cde-4309-9f7c-4eccce3fde28','9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','66458b1b-c92f-43fa-8eba-e428892ce88a','e38c12a7-43cb-421a-a36e-7ef0d32517fa','dc7b2b73-74de-4fb8-9274-a5967ca444f9','30b5d53c-d247-4f04-9b50-c0f728e65cf9','06e6f3e7-0293-469d-a338-11a610f3e71b','6c285c60-022a-4a00-b172-87df97f16a2f','94786475-832c-4f97-aab7-bf6fbbe2236b','c85a52b9-c3b4-4a76-951c-bb40edeb3adb','f175019d-5a93-4cd4-aabc-e7e79445f15a','84104c49-0af4-4323-a56b-b67002a422d9','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc']::uuid[], '[{"step":1,"text":"낙지는 살짝 데치고 한입 크기로 썬다.","imageUrl":null},{"step":2,"text":"오이와 당근, 표고, 가지는 얇게 동그란 모양으로 썰고 가지와 표고를 살짝 구워준다.","imageUrl":null},{"step":3,"text":"설탕, 식초, 물로 초절이 양념을 만들어 오이, 당근, 구운 가지와 표고를 절인다.","imageUrl":null},{"step":4,"text":"③의 재료에 낙지를 올린 후 데친 미나리로 감싼다.","imageUrl":null},{"step":5,"text":"사과를 잘게 다져서 준비한다.","imageUrl":null},{"step":6,"text":"사과, 간장, 고춧가루, 설탕, 식초, 깨로 소스를 만들어 초말이와 제공한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317112606_1584411966414.JPG', 46.7, 7.3, 3.7, 0.3, 67.5),
  ('3197', '삼각김밥 빵', '기타', ' 쌀가루 200g, 우유 80g, 물 15ml, 르뱅 발효종 160g, 달걀 50g(1개), 소금 3g, 올리브유 25g, 양파 30g, 당근 30g, 먹물 가루 30g 
 토마토 250g, 양파 150g, 피망 60g, 마늘 20g, 닭가슴살 300g, 오레가노 5g, 바질가루 5g, 월계수잎 5g, 후추 5g, 소금5g, 고추5g, 고춧가루5g,모짜렐라 치즈 50g', '["쌀가루","우유","물","르뱅 발효종","달걀","소금","올리브유","양파","당근","먹물 가루","토마토","피망","마늘","닭가슴살","오레가노","바질가루","월계수잎","후추","고추","고춧가루","모짜렐라 치즈"]'::jsonb, ARRAY['4cb11562-015f-4ab5-969f-0ea8483a0b42','e937397f-54e2-49df-997a-f393c58360be','94786475-832c-4f97-aab7-bf6fbbe2236b','c7d438a6-34d6-423f-905d-446b839e2f39','2cf0c12b-f248-4012-8f53-303c730a7b3d','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','e38c12a7-43cb-421a-a36e-7ef0d32517fa','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','df459e6f-3515-45d5-8c9a-9d37b6249379','fc6e31ce-388e-45cd-956b-b238b9134eb1','e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','cdbae946-7ca4-4f8d-8a3c-5bb295961ad6','ba9e5a79-cab3-4af0-942b-0b35fd745150','043a9631-bb6e-42e6-9673-4943457502fb','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','30b5d53c-d247-4f04-9b50-c0f728e65cf9','84104c49-0af4-4323-a56b-b67002a422d9','4e0e50d8-ce94-4636-82f5-5bd5ac15d74c']::uuid[], '[{"step":1,"text":"(속재료) 양파, 마늘, 토마토, 파프리카, 닭가슴살을 다져 올리브유를 두른 팬에 볶아준 후에 월계수 잎을 넣고 졸이다가 고추, 오레가노, 바질가루, 고춧가루, 소금, 후추를 넣고 간을 맞춘다.","imageUrl":null},{"step":2,"text":"반죽재료를 모두 넣고 1단으로 믹싱한 후 올리브유를 넣고 최종단계 직전까지 믹싱이 되면 다진 양파와 당근을 넣고 최종단계까지 믹싱한다.","imageUrl":null},{"step":3,"text":"1차 발효(30분~40분)후에 반죽을 각 70g씩 총 3개로 분할하여 둥글리기 한 후 랩을 덮어 중간발효(10분)를 한다.","imageUrl":null},{"step":4,"text":"반죽을 손 위에 놓고 납작하게 눌러서 속재료 40g과 모짜렐라치즈 10g을 넣고 봉합 한 뒤에 삼각형 모양으로 만든다.\r\n★이음새가 벌어지면 구우면서 반죽이 터져지니 꼼꼼히 붙여주세요.","imageUrl":null},{"step":5,"text":"팬닝 후 2차 발효(30분)를 한다.","imageUrl":null},{"step":6,"text":"윗불 160℃, 아랫불 180℃에서 15분 동안 굽는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129053949_1611909589857.jpg', 212, 31.83, 10.81, 4.64, 3.79),
  ('3235', '병아리콩 컵케이크', '후식', '불린 병아리콩(100g), 바나나(1½개), 무가당 코코아 파우더(3g), 다크초콜릿(30g), 아몬드가루(50g), 달걀노른자(1개), 우유(130g), 식용유(10ml), 아몬드 슬라이스(1g), 병아리콩 삶은 물(50ml), 무가당 휘핑크림(50g), 올리고당(15g), 바나나(½개)', '["불린 병아리콩","바나나","무가당 코코아 파우더","다크초콜릿","아몬드가루","달걀노른자","우유","식용유","아몬드 슬라이스","병아리콩 삶은 물","무가당 휘핑크림","올리고당"]'::jsonb, ARRAY['1a4b39f8-b581-46dc-bd7e-289cd6160711','52ba316f-8e7f-415f-8079-9a9d674c9adf','c7d438a6-34d6-423f-905d-446b839e2f39','e937397f-54e2-49df-997a-f393c58360be','a7a59e81-de3d-4893-b56a-b2218732a25b','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d']::uuid[], '[{"step":1,"text":"불린 병아리콩은 끓는 물(3컵)에 30~40분간 끓여 건지고, 병아리콩 삶은 물(50㎖)은 한 김 식혀 냉장실에 넣는다.","imageUrl":null},{"step":2,"text":"삶은 병아리콩, 바나나(½개), 무가당 코코아 파우더, 다크 초콜릿, 아몬드가루, 달걀노른자, 우유는 믹서에 넣어 곱게 갈아 반죽을 만든다.","imageUrl":null},{"step":3,"text":"중간 불로 달군 팬에 식용유(10㎖)를 두른 뒤 컵 사이즈에 맞게 반죽을 올려 앞뒤로 노릇하게 굽는다.","imageUrl":null},{"step":4,"text":"냉장실에서 병아리콩물을 꺼내 휘핑해 두고, 무가당 휘핑크림에 올리고당을 넣고 휘핑한 뒤 바나나(½개)를 으깨 고루 섞는다.","imageUrl":null},{"step":5,"text":"④의 병아리콩물과 바나나무가당크림을 모두 섞고, 바나나(1개)는 얇게 썬다.","imageUrl":null},{"step":6,"text":"컵에 구운 시트 → 얇게 썬 바나나 → 크림을 반복하여 쌓고 아몬드 슬라이스를 올린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20221208/20221208043938_1670485178488.jpg', 825.2, 70.6, 21.5, 50.8, 91.6),
  ('3292', '양파토마토스튜', '국&찌개', ' 마늘(4쪽), 토마토(2개), 양파(1개), 월계수잎(2장), 육수용 멸치(½컵), 다시마(5×5cm, 2장)', '["마늘","토마토","양파","월계수잎","육수용 멸치","다시마"]'::jsonb, ARRAY['fc6e31ce-388e-45cd-956b-b238b9134eb1','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','043a9631-bb6e-42e6-9673-4943457502fb','84032a7e-ec18-44d5-ab30-c7b960ca5ca9']::uuid[], '[{"step":1,"text":"물(8컵)에 육수 재료와 마늘(2쪽)을 넣어 끓으면 다시마를 건진 뒤 약한 불 로 30분간 더 끓여 육수를 만든다.","imageUrl":null},{"step":2,"text":"토마토는 꼭지를 제거하고, 열십자로 칼집을 낸 뒤 끓는 물에 30초간 데쳐 찬물에 담근다.","imageUrl":null},{"step":3,"text":"데친 토마토는 껍질을 벗긴 뒤 씨를 제거하고, 1×1cm 크기로 썬다.","imageUrl":null},{"step":4,"text":"양파는 3mm 두께로 채 썰고, 마늘(2쪽)은 1mm 두께로 채 썬다.","imageUrl":null},{"step":5,"text":"중간 불로 달군 마른 냄비에 채 썬 양파와 물(1Ts)을 넣어 진한 갈색이 될 때까지 볶는다.","imageUrl":null},{"step":6,"text":"토마토를 넣어 으깨가며 5분간 볶고, 육수(6컵), 월계수잎, 채 썬 마늘을 넣어 10분간 끓이고 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9bVw', 36.2, 4.9, 1.6, 1.2, 155.8),
  ('3294', '황금팽이 비빔국수', '기타', ' 황금팽이버섯(400g), 양파( 개), 상추(2장), 깻잎(2장), 오이(½개), 천도복숭아(½개), 새우살(½컵), 게살(½컵), 고춧가루(3Ts), 물(3Ts), 현미식초(1.5Ts), 저염 간장(1.5Ts), 다진 마늘(0.5Ts), 참기름(1.5Ts), 참깨(0.3Ts)', '["황금팽이버섯","양파","상추","깻잎","오이","천도복숭아","새우살","게살","고춧가루","물","현미식초","저염 간장","다진 마늘","참기름","참깨"]'::jsonb, ARRAY['61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','1389717e-81e4-4350-96d4-d627d851aa10','3c38eb1c-6ef4-4bb8-82be-74f679ce9e91','9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','6f10b4ad-53a2-4a07-ba89-19a6b074373d','84104c49-0af4-4323-a56b-b67002a422d9','94786475-832c-4f97-aab7-bf6fbbe2236b','6c285c60-022a-4a00-b172-87df97f16a2f','f175019d-5a93-4cd4-aabc-e7e79445f15a','fc6e31ce-388e-45cd-956b-b238b9134eb1','0c0ade94-cfd8-4104-b44c-40e942cac482','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc']::uuid[], '[{"step":1,"text":"황금팽이버섯은 밑동을 자른 뒤 낱낱이 가르고, 양파, 상추, 깻잎, 오이는 채 썰고, 천도복숭아는 웨지 모양으로 썬다.","imageUrl":null},{"step":2,"text":"끓는 물에 황금 팽이버섯을 넣어 5분간 삶아 건진 뒤 찬물에 헹궈 물기를 뺀다.","imageUrl":null},{"step":3,"text":"같은 물에 새우살과 게살을 30초간 데쳐 건진 뒤 찬물에 헹궈 물기를 뺀다.","imageUrl":null},{"step":4,"text":"양념장을 만든다.","imageUrl":null},{"step":5,"text":"손질한 재료를 그릇에 담고, 양념장을 곁들여 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9cBO', 102.7, 6.9, 12.8, 2.6, 314.7),
  ('3295', '맛살 미역줄기전', '반찬', ' 미역 줄기(1팩=300g), 양파(½개), 맛살(135g), 건새우(1컵), 부침가루(1컵), 튀김가루(½컵), 탄산수(1컵), 아보카도유(1Ts)', '["미역 줄기","양파","맛살","건새우","부침가루","튀김가루","탄산수","아보카도유"]'::jsonb, ARRAY['61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','6f10b4ad-53a2-4a07-ba89-19a6b074373d','aab3b0b9-d346-4697-a1c8-1b1530153788','20a151f5-d44f-48d8-bd67-958886b649d6']::uuid[], '[{"step":1,"text":"미역 줄기는 흐르는 물에 여러 번 헹구고, 찬물에 1시간 정도 담가둔다.","imageUrl":null},{"step":2,"text":"미역 줄기는 한입 크기로 썰고, 양파는 얇게 채 썰고, 맛살은 낱낱이 가른다.","imageUrl":null},{"step":3,"text":"끓는 물에 맛살을 살짝 데쳐 건진 뒤 물기를 제거한다.","imageUrl":null},{"step":4,"text":"반죽 재료를 고루 섞은 뒤 손질한 재료를 넣어 대충 섞는다.","imageUrl":null},{"step":5,"text":"중간 불로 달군 팬에 아보카도유를 두른 뒤 반죽을 적당한 크기로 떼어 올리고, 건새우를 얹는다.","imageUrl":null},{"step":6,"text":"반죽이 불투명해지면 뒤집고, 앞뒤로 노릇하게 구워 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9ktU', 128.2, 11.9, 4.1, 7.2, 519.2),
  ('3297', '해산물샐러드와 미나리소스', '반찬', ' 새송이버섯(1개), 방울토마토(200g), 오징어(1마리), 칵테일새우(200g), 후춧가루(약간), 다진 마늘(1Ts), 올리브유(1Ts), 레몬즙(1Ts), 후춧가루(약간), 미나리(50g), 깻잎(2장), 마늘(2쪽), 올리브유(3.5Ts), 체더치즈(2.5Ts), 아몬드(5개)', '["새송이버섯","방울토마토","오징어","칵테일새우","후춧가루","다진 마늘","올리브유","레몬즙","미나리","깻잎","마늘","체더치즈","아몬드"]'::jsonb, ARRAY['3f94371a-728f-49ae-8ea9-1a1e87b68048','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','4d148f68-08e0-4599-8953-595db492bf23','6f10b4ad-53a2-4a07-ba89-19a6b074373d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','fc6e31ce-388e-45cd-956b-b238b9134eb1','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','dc7b2b73-74de-4fb8-9274-a5967ca444f9','3c38eb1c-6ef4-4bb8-82be-74f679ce9e91','52ba316f-8e7f-415f-8079-9a9d674c9adf']::uuid[], '[{"step":1,"text":"새송이버섯은 모양대로 도톰하게 썰고, 방울토마토는 꼭지를 제거한 뒤 열십자 모양을 내고, 오징어 몸통 부분에 사선으로 칼집을 낸 뒤 후춧가루를 뿌린다.","imageUrl":null},{"step":2,"text":"칵테일새우는 양념에 버무린 뒤 20분간 재운다.","imageUrl":null},{"step":3,"text":"중간 불로 달군 마른 팬에 새송이버섯, 방울토마토를 넣어 노릇하게 구워 꺼낸다.","imageUrl":null},{"step":4,"text":"같은 팬에 새우, 오징어를 넣어 겉면의 색이 변할 때까지 구워 꺼낸다.","imageUrl":null},{"step":5,"text":"믹서에 페스토 재료를 넣어 곱게 간다.","imageUrl":null},{"step":6,"text":"그릇에 미나리 페스토를 담고, 손질한 재료를 올려 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9nAC', 216.9, 8.6, 23.9, 9.6, 454.2),
  ('3298', '매운요거트 토마토샐러드', '반찬', ' 토마토(2개), 양파(¼개), 감자(¼개), 노랑 파프리카(¼개), 브로콜리(¼개), 새우(4마리) 고추기름(1Ts), 후춧가루(0.3Ts), 다진 마늘(0.3Ts), 플레인 요거트(½컵), 고추장(0.3Ts)', '["토마토","양파","감자","노랑 파프리카","브로콜리","새우 고추기름","후춧가루","다진 마늘","플레인 요거트","고추장"]'::jsonb, ARRAY['aa597bcd-596b-4cbe-a2c4-3da0d060cb50','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','20894da1-739d-4d52-b5fe-4943bd3492d5','5e79d288-1400-4817-bd20-e5e6041821b1','9bf64924-ce53-42bb-849e-7294416e95d6','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','fc6e31ce-388e-45cd-956b-b238b9134eb1','bb41a88a-ea2b-4830-876d-91fe7f640296','84b8828b-7396-4dcb-a5d6-44e3cd5a8fdb']::uuid[], '[{"step":1,"text":"토마토는 윗부분을 약간 자른 뒤 속을 파낸다.","imageUrl":null},{"step":2,"text":"양파, 감자, 노랑 파프리카, 브로콜리, 새우는 1×1cm 크기로 썬다.","imageUrl":null},{"step":3,"text":"중간 불로 달군 팬에 고추기름을 두르고, 손질한 채소를 넣어 양파가 투명해질 때까지 볶는다.","imageUrl":null},{"step":4,"text":"새우와 후춧가루를 넣은 뒤 고루 섞으며 볶는다.","imageUrl":null},{"step":5,"text":"고추장 요거트 드레싱을 만든다.","imageUrl":null},{"step":6,"text":"토마토 속에 ④의 볶은 재료를 담고, 고추장 요거트 드레싱을 곁들여 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9nNW', 88.9, 6.1, 7.8, 3.7, 198.3),
  ('3689', '초코타르트', '후식', ' 아몬드가루 90g, 무가당 코코아가루① 12g, 귀리 30g, 코코넛오일 20g, 알룰로스① 20g, 소금 1g, 무가당 코코아가루② 12g, 땅콩버터 12g, 알룰로스② 55g, 아몬드우유 60ml, 그릭요거트 42g, 알룰로스③ 2g', '["아몬드가루","무가당 코코아가루①","귀리","코코넛오일","알룰로스①","소금","무가당 코코아가루②","땅콩버터","알룰로스②","아몬드우유","그릭요거트","알룰로스③"]'::jsonb, ARRAY['52ba316f-8e7f-415f-8079-9a9d674c9adf','c15a4a69-31ab-450d-943a-2a7bb2230857','2cf0c12b-f248-4012-8f53-303c730a7b3d','02c78319-0bf6-45e0-8a7b-7546e1e47ba7']::uuid[], '[{"step":1,"text":"볼에 아몬드가루, 무가당\r\n코코아가루①을 체 쳐서 넣고 귀리,\r\n코코넛오일, 알룰로스①, 소금을 넣고\r\n섞어 반죽을 만든다.","imageUrl":null},{"step":2,"text":"반죽은 냉장고에서 30분 동안\r\n휴지한다.","imageUrl":null},{"step":3,"text":"볼에 무가당 코코아가루②를 체 쳐서\r\n넣고 땅콩버터, 알룰로스②를 넣는다.\r\n완전히 섞이면 아몬드우유를 넣고\r\n섞어 초코필링을 만든다.","imageUrl":null},{"step":4,"text":"냉동실에서 30분 동안 굳힌\r\n그릭요거트에 알룰로스③을 섞어\r\n숟가락으로 모양을 잡아 그릭요거트\r\n토핑을 만든다.","imageUrl":null},{"step":5,"text":"머핀 틀에 코코넛오일을 바르고\r\n반죽을 넣어 타르트지 모양을 잡는다.\r\n170°C로 예열한 오븐에 20분 동안\r\n구운 후 완전히 식힌다.","imageUrl":null},{"step":6,"text":"초코필링을 채우고 그릭요거트\r\n토핑을 올려 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20251023/20251023104957_1761184197030.jpg', 154.5, 18.7, 5.4, 6.5, 44.3)
on conflict (id) do update set
  name = excluded.name,
  category = excluded.category,
  raw_ingredients_text = excluded.raw_ingredients_text,
  parsed_ingredients = excluded.parsed_ingredients,
  matched_ingredient_ids = excluded.matched_ingredient_ids,
  cooking_steps = excluded.cooking_steps,
  image_url = excluded.image_url,
  nutrition_kcal = excluded.nutrition_kcal,
  nutrition_carb = excluded.nutrition_carb,
  nutrition_protein = excluded.nutrition_protein,
  nutrition_fat = excluded.nutrition_fat,
  nutrition_sodium = excluded.nutrition_sodium,
  loaded_at = now();
